@Controller('query')
@UseGuards(JwtAuthGuard, RolesGuard)
@Roles('admin', 'vendor')
export class QueryController {
  constructor(private readonly queryService: QueryService) {}

  @Post()
  execute(@Body() dto: PowerQueryDto, @Req() req: Request) {
