119	    const actorIds = [...new Set(items.map((i) => i.actorId).filter(Boolean))];
120	    const userMap: Record<string, string> = {};
121	    if (actorIds.length > 0) {
122	      const userRepo = this.auditRepo.manager.getRepository(User);
123	      const users = await userRepo
124	        .createQueryBuilder('u')
125	        .where('u.id IN (:...ids)', { ids: actorIds })
126	        .getMany();
127	      for (const u of users) {
128	        userMap[u.id] = u.username;
129	      }
130	    }
131	
132	    const enriched = items.map((item) => ({
133	      ...item,
134	      actorUsername: userMap[item.actorId] ?? 'unknown',
135	    }));
136	
137	    return { items: enriched, total };
138	  }
139	
140	  async verifyEntry(id: string): Promise<{ valid: boolean; entry: AuditLog }> {
141	    const entry = await this.auditRepo.findOne({ where: { id } });
142	    if (!entry) {
143	      throw new Error('Audit entry not found');
144	    }
145	
146	    const recomputedPayload = (entry.prevHash ?? '') + JSON.stringify({
147	      action: entry.action,
148	      actorId: entry.actorId,
149	      entityType: entry.entityType,
150	      entityId: entry.entityId ?? null,
151	      before: entry.before ?? null,
152	      after: entry.after ?? null,
153	      ts: entry.createdAt.toISOString(),
154	    });
155	    const recomputedHash = crypto
156	      .createHash('sha256')
157	      .update(recomputedPayload)
158	      .digest('hex');
159	
160	    return {
161	      valid: recomputedHash === entry.hash,
162	      entry,
163	    };
164	  }
165	}
