99	  private async checkMultiAccountDevice(
100	    userId: string,
101	    deviceFingerprint: string,
102	  ): Promise<RiskFlag | null> {
103	    const users = await this.userRepo.find();
104	    let matchCount = 0;
105	
106	    for (const user of users) {
107	      if (user.id === userId) continue;
108	      if (!user.deviceFingerprint) continue;
109	      try {
110	        const decrypted = this.encryption.decrypt(user.deviceFingerprint);
111	        if (decrypted === deviceFingerprint) matchCount++;
112	      } catch {
113	        continue;
114	      }
115	    }
116	
117	    if (matchCount >= 2) {
118	      return {
119	        riskFlag: 'multi_account_device',
120	        detail: `Device fingerprint found on ${matchCount + 1} accounts`,
121	      };
122	    }
123	    return null;
124	  }
