139	  async suggest(q: string): Promise<string[]> {
140	    if (!q || q.length < 1) return [];
141	    const corrected = this.correctTypos(q);
142	    const pattern = `%${corrected}%`;
143	
144	    const breeds = await this.listingRepo
145	      .createQueryBuilder('l')
146	      .select('DISTINCT l.breed', 'value')
147	      .where('l.breed ILIKE :pattern', { pattern })
148	      .andWhere('l.status = :status', { status: ListingStatus.ACTIVE })
149	      .andWhere('l.deletedAt IS NULL')
150	      .limit(5)
151	      .getRawMany();
