22	const CONV_RATE_LIMIT_WINDOW_MS = 10 * 60 * 1000;
23	
24	@Injectable()
25	export class ConversationsService {
26	  constructor(
27	    @InjectRepository(Conversation)
28	    private readonly convRepo: Repository<Conversation>,
29	    @InjectRepository(Message)
30	    private readonly msgRepo: Repository<Message>,
31	    @InjectRepository(Listing)
32	    private readonly listingRepo: Repository<Listing>,
33	    @InjectRepository(RateLimitEvent)
34	    private readonly rateLimitRepo: Repository<RateLimitEvent>,
35	    @InjectRepository(CannedResponse)
36	    private readonly cannedRepo: Repository<CannedResponse>,
37	    private readonly auditService: AuditService,
38	  ) {}
39	
40	  async findAll(
41	    userId: string,
42	    role: string,
43	    filters: ConversationFiltersDto,
44	  ): Promise<Conversation[]> {
45	    const qb = this.convRepo
46	      .createQueryBuilder('c')
47	      .leftJoinAndSelect('c.listing', 'listing');
48	
49	    if (role === 'vendor') {
50	      qb.where('c.vendorId = :userId', { userId });
51	    } else if (role === 'shopper') {
52	      qb.where(':userId = ANY(c.shopperIds)', { userId });
53	    }
54	
55	    if (filters.archived !== undefined) {
56	      qb.andWhere('c.isArchived = :archived', { archived: filters.archived });
57	    }
58	    if (filters.listingId) {
59	      qb.andWhere('c.listingId = :listingId', { listingId: filters.listingId });
60	    }
61	    if (filters.keyword) {
62	      qb.andWhere('listing.title ILIKE :kw', { kw: `%${filters.keyword}%` });
63	    }
64	    if (filters.startDate) {
65	      qb.andWhere('c.createdAt >= :startDate', { startDate: new Date(filters.startDate) });
66	    }
67	    if (filters.endDate) {
68	      qb.andWhere('c.createdAt <= :endDate', { endDate: new Date(filters.endDate) });
69	    }
70	
71	    return qb.orderBy('c.createdAt', 'DESC').getMany();
72	  }
73	
74	  async create(shopperId: string, listingId: string): Promise<Conversation> {
75	    await this.enforceConversationRateLimit(shopperId);
76	
77	    const listing = await this.listingRepo.findOne({ where: { id: listingId } });
78	    if (!listing) throw new NotFoundException('Listing not found');
79	
80	    const existing = await this.convRepo
81	      .createQueryBuilder('c')
82	      .where('c.listingId = :listingId', { listingId })
83	      .andWhere(':shopperId = ANY(c.shopperIds)', { shopperId })
84	      .getOne();
85	
86	    if (existing) return existing;
87	
88	    const conv = this.convRepo.create({
89	      listingId,
90	      vendorId: listing.vendorId,
91	      shopperIds: [shopperId],
92	    });
93	    const saved = await this.convRepo.save(conv);
94	
95	    await this.rateLimitRepo.save(
96	      this.rateLimitRepo.create({ userId: shopperId, action: 'create_conversation' }),
97	    );
98	
99	    await this.auditService.log({
100	      action: 'conversation.create',
101	      actorId: shopperId,
102	      entityType: 'conversation',
103	      entityId: saved.id,
104	      after: { id: saved.id, listingId, vendorId: listing.vendorId } as unknown as Record<string, unknown>,
105	    });
106	
107	    return saved;
108	  }
109	
110	  async getConversationWithMessages(
111	    conversationId: string,
112	    userId: string,
113	    role: string,
114	  ): Promise<{ conversation: Conversation; messages: Message[] }> {
115	    const conv = await this.assertAccess(conversationId, userId, role);
116	
117	    const qb = this.msgRepo
118	      .createQueryBuilder('m')
119	      .where('m.conversationId = :conversationId', { conversationId: conv.id })
120	      .orderBy('m.createdAt', 'ASC');
121	
122	    if (role === 'shopper') {
123	      qb.andWhere('m.isInternal = false');
124	    }
125	
126	    const messages = await qb.getMany();
127	    return { conversation: conv, messages };
128	  }
129	
130	  async sendMessage(
131	    conversationId: string,
132	    senderId: string,
133	    role: string,
134	    dto: SendMessageDto,
135	  ): Promise<Message> {
136	    const conv = await this.assertAccess(conversationId, senderId, role);
137	
138	    if (dto.type === 'text' && !dto.content) {
139	      throw new BadRequestException('Text messages require content');
140	    }
141	    if (dto.type === 'voice' && !dto.audioUrl) {
142	      throw new BadRequestException('Voice messages require audioUrl');
143	    }
144	    if (dto.isInternal && role !== 'vendor' && role !== 'admin') {
145	      throw new ForbiddenException('Only vendors and admins can send internal messages');
146	    }
147	
148	    const msg = this.msgRepo.create({
149	      conversationId: conv.id,
150	      senderId,
151	      content: dto.content ?? '',
152	      type: dto.type === 'voice' ? MessageType.VOICE : MessageType.TEXT,
153	      audioUrl: dto.audioUrl ?? null,
154	      isInternal: dto.isInternal ?? false,
155	    });
156	    const saved = await this.msgRepo.save(msg);
157	
158	    await this.auditService.log({
159	      action: 'message.create',
160	      actorId: senderId,
161	      entityType: 'message',
162	      entityId: saved.id,
163	      after: {
164	        id: saved.id,
165	        conversationId: conv.id,
166	        type: saved.type,
167	        isInternal: saved.isInternal,
168	      } as unknown as Record<string, unknown>,
169	    });
170	
171	    return saved;
172	  }
173	
174	  async archive(
175	    conversationId: string,
176	    userId: string,
177	    role: string,
178	  ): Promise<Conversation> {
179	    const conv = await this.assertAccess(conversationId, userId, role);
180	
181	    if (role !== 'vendor' && role !== 'admin') {
182	      throw new ForbiddenException('Only vendors and admins can archive conversations');
183	    }
184	
185	    conv.isArchived = true;
186	    const saved = await this.convRepo.save(conv);
187	
188	    await this.auditService.log({
189	      action: 'conversation.archive',
190	      actorId: userId,
191	      entityType: 'conversation',
192	      entityId: conversationId,
193	    });
194	
195	    return saved;
196	  }
197	
198	  async getCannedResponses(): Promise<CannedResponse[]> {
199	    return this.cannedRepo.find({ order: { createdAt: 'DESC' } });
200	  }
201	
202	  async createCannedResponse(
203	    dto: CreateCannedResponseDto,
204	    createdBy: string,
205	  ): Promise<CannedResponse> {
206	    const cr = this.cannedRepo.create({
207	      title: dto.title,
208	      body: dto.body,
209	      createdBy,
210	    });
211	    const saved = await this.cannedRepo.save(cr);
212	
213	    await this.auditService.log({
214	      action: 'canned_response.create',
215	      actorId: createdBy,
216	      entityType: 'canned_response',
217	      entityId: saved.id,
218	      after: { id: saved.id, title: saved.title } as unknown as Record<string, unknown>,
219	    });
220	
221	    return saved;
222	  }
223	
224	  private async assertAccess(
225	    conversationId: string,
226	    userId: string,
227	    role: string,
228	  ): Promise<Conversation> {
229	    const conv = await this.convRepo.findOne({ where: { id: conversationId } });
230	    if (!conv) throw new NotFoundException('Conversation not found');
231	
232	    const isVendor = role === 'vendor' && conv.vendorId === userId;
233	    const isShopper = role === 'shopper' && conv.shopperIds.includes(userId);
234	    const isAdmin = role === 'admin';
235	
236	    if (!isVendor && !isShopper && !isAdmin) {
237	      throw new ForbiddenException('Access denied to this conversation');
238	    }
239	    return conv;
240	  }
241	
242	  private async enforceConversationRateLimit(userId: string): Promise<void> {
243	    const windowStart = new Date(Date.now() - CONV_RATE_LIMIT_WINDOW_MS);
244	    const count = await this.rateLimitRepo.count({
245	      where: {
246	        userId,
247	        action: 'create_conversation',
248	        createdAt: MoreThanOrEqual(windowStart),
249	      },
250	    });
251	    if (count >= CONV_RATE_LIMIT_MAX) {
252	      throw new HttpException(
253	        'Rate limit exceeded: max 10 new conversations per 10 minutes',
254	        HttpStatus.TOO_MANY_REQUESTS,
255	      );
256	    }
257	  }
258	}
