31	  async findAll(
32	    userId: string,
33	    role: string,
34	    filters: SettlementFiltersDto,
35	  ): Promise<Settlement[]> {
36	    const qb = this.settlementRepo.createQueryBuilder('s');
37	
38	    if (role === 'vendor') {
39	      qb.where('s.vendorId = :userId', { userId });
40	    }
41	    if (filters.month) {
42	      qb.andWhere('s.month = :month', { month: filters.month });
43	    }
44	    if (filters.status) {
