51	  async findOne(id: string): Promise<{
52	    settlement: Settlement;
53	    variance: { expected: number; actual: number; variance: number; variancePercent: number };
54	  }> {
55	    const settlement = await this.settlementRepo.findOne({ where: { id } });
56	    if (!settlement) throw new NotFoundException('Settlement not found');
57	
58	    const expected = Number(settlement.totalCharges);
59	    const actual = expected;
60	    const variance = actual - expected;
61	    const variancePercent = expected > 0 ? (variance / expected) * 100 : 0;
62	
63	    return {
64	      settlement,
65	      variance: {
66	        expected: round(expected),
67	        actual: round(actual),
68	        variance: round(variance),
69	        variancePercent: round(variancePercent),
70	      },
71	    };
72	  }
