1	import { FreightService, FreightParams } from '../backend/src/settlements/freight.service';
2	
3	const service = new FreightService();
4	
5	function calc(overrides: Partial<FreightParams> = {}) {
6	  return service.calculate({
7	    distanceMiles: 100,
8	    weightLbs: 10,
9	    dimWeightLbs: 5,
10	    isOversized: false,
11	    isWeekend: false,
12	    ...overrides,
13	  });
14	}
15	
16	describe('FreightService', () => {
17	  describe('base cost tiers', () => {
18	    it('0-50 miles → $5', () => {
19	      expect(calc({ distanceMiles: 30 }).baseCost).toBe(5);
20	      expect(calc({ distanceMiles: 50 }).baseCost).toBe(5);
21	    });
22	
23	    it('51-200 miles → $12', () => {
24	      expect(calc({ distanceMiles: 51 }).baseCost).toBe(12);
25	      expect(calc({ distanceMiles: 200 }).baseCost).toBe(12);
26	    });
27	
28	    it('201-500 miles → $25', () => {
29	      expect(calc({ distanceMiles: 201 }).baseCost).toBe(25);
30	      expect(calc({ distanceMiles: 500 }).baseCost).toBe(25);
31	    });
32	
33	    it('500+ miles → $45', () => {
34	      expect(calc({ distanceMiles: 501 }).baseCost).toBe(45);
35	      expect(calc({ distanceMiles: 1000 }).baseCost).toBe(45);
36	    });
37	  });
38	
39	  describe('billable weight', () => {
40	    it('uses actual weight when greater than dim weight', () => {
41	      expect(calc({ weightLbs: 20, dimWeightLbs: 10 }).billableWeight).toBe(20);
42	    });
43	
44	    it('uses dim weight when greater than actual weight', () => {
45	      expect(calc({ weightLbs: 10, dimWeightLbs: 25 }).billableWeight).toBe(25);
46	    });
47	
48	    it('equal weights uses either (max)', () => {
49	      expect(calc({ weightLbs: 15, dimWeightLbs: 15 }).billableWeight).toBe(15);
50	    });
51	  });
52	
53	  describe('oversized surcharge', () => {
54	    it('adds exactly $15.00 when oversized', () => {
55	      expect(calc({ isOversized: true }).oversizedSurcharge).toBe(15);
56	    });
57	
58	    it('$0 when not oversized', () => {
59	      expect(calc({ isOversized: false }).oversizedSurcharge).toBe(0);
60	    });
61	  });
62	
63	  describe('weekend surcharge', () => {
64	    it('is exactly 5% of subtotal before weekend', () => {
65	      const result = calc({ isWeekend: true });
66	      expect(result.weekendSurcharge).toBe(
67	        Math.round(result.subtotalBeforeWeekend * 0.05 * 100) / 100,
68	      );
69	    });
70	
71	    it('is $0 on weekdays', () => {
72	      expect(calc({ isWeekend: false }).weekendSurcharge).toBe(0);
73	    });
74	  });
75	
76	  describe('sales tax', () => {
77	    it('is 8.5% of pre-tax total', () => {
78	      const result = calc();
79	      expect(result.salesTax).toBe(
80	        Math.round(result.subtotalBeforeTax * 0.085 * 100) / 100,
81	      );
82	    });
83	  });
84	
85	  describe('combined scenario', () => {
86	    it('300mi, 20lbs, dimWeight 25lbs, oversized, weekend', () => {
87	      const result = calc({
88	        distanceMiles: 300,
89	        weightLbs: 20,
90	        dimWeightLbs: 25,
91	        isOversized: true,
92	        isWeekend: true,
93	      });
94	
95	      expect(result.billableWeight).toBe(25);
96	      expect(result.baseCost).toBe(25);
97	      expect(result.perPoundCharge).toBe(2);
98	      expect(result.oversizedSurcharge).toBe(15);
99	      expect(result.subtotalBeforeWeekend).toBe(42);
100	      expect(result.weekendSurcharge).toBe(2.1);
101	      expect(result.subtotalBeforeTax).toBe(44.1);
102	      expect(result.salesTax).toBe(3.75);
103	      expect(result.total).toBe(47.85);
104	    });
