11	export interface FreightBreakdown {
12	  billableWeight: number;
13	  baseCost: number;
14	  perPoundCharge: number;
15	  oversizedSurcharge: number;
16	  subtotalBeforeWeekend: number;
17	  weekendSurcharge: number;
18	  subtotalBeforeTax: number;
19	  salesTax: number;
20	  total: number;
21	}
22	
23	const TAX_RATE = 0.085;
24	const PER_POUND_RATE = 0.08;
25	const OVERSIZED_FEE = 15.0;
26	const WEEKEND_RATE = 0.05;
27	
28	@Injectable()
29	export class FreightService {
30	  calculate(params: FreightParams): FreightBreakdown {
31	    const billableWeight = Math.max(params.weightLbs, params.dimWeightLbs);
32	
33	    let baseCost: number;
34	    if (params.distanceMiles <= 50) baseCost = 5;
35	    else if (params.distanceMiles <= 200) baseCost = 12;
36	    else if (params.distanceMiles <= 500) baseCost = 25;
37	    else baseCost = 45;
38	
39	    const perPoundCharge = round(billableWeight * PER_POUND_RATE);
40	    const oversizedSurcharge = params.isOversized ? OVERSIZED_FEE : 0;
41	    const subtotalBeforeWeekend = round(baseCost + perPoundCharge + oversizedSurcharge);
42	    const weekendSurcharge = params.isWeekend
43	      ? round(subtotalBeforeWeekend * WEEKEND_RATE)
44	      : 0;
45	    const subtotalBeforeTax = round(subtotalBeforeWeekend + weekendSurcharge);
46	    const salesTax = round(subtotalBeforeTax * TAX_RATE);
47	    const total = round(subtotalBeforeTax + salesTax);
48	
49	    return {
50	      billableWeight,
51	      baseCost,
52	      perPoundCharge,
53	      oversizedSurcharge,
54	      subtotalBeforeWeekend,
55	      weekendSurcharge,
56	      subtotalBeforeTax,
57	      salesTax,
58	      total,
59	    };
60	  }
61	}
62	
63	function round(n: number): number {
64	  return Math.round(n * 100) / 100;
65	}
