1	import { Injectable } from '@nestjs/common';
2	import * as crypto from 'crypto';
3	
4	const ALGORITHM = 'aes-256-cbc';
5	const IV_LENGTH = 16;
6	const ENC_PREFIX = 'enc:';
7	
8	@Injectable()
9	export class EncryptionService {
10	  private readonly key: Buffer;
11	
12	  constructor() {
13	    const raw = process.env.FIELD_ENCRYPTION_KEY ?? 'local_dev_encryption_key_change_in_prod';
14	    this.key = crypto.createHash('sha256').update(raw).digest();
15	  }
16	
17	  encrypt(plaintext: string): string {
18	    if (!plaintext) return plaintext;
19	    if (plaintext.startsWith(ENC_PREFIX)) return plaintext;
20	    const iv = crypto.randomBytes(IV_LENGTH);
21	    const cipher = crypto.createCipheriv(ALGORITHM, this.key, iv);
22	    const encrypted = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
23	    return ENC_PREFIX + iv.toString('hex') + ':' + encrypted.toString('hex');
24	  }
25	
26	  decrypt(ciphertext: string): string {
27	    if (!ciphertext) return ciphertext;
28	    if (!ciphertext.startsWith(ENC_PREFIX)) return ciphertext;
29	    try {
30	      const payload = ciphertext.slice(ENC_PREFIX.length);
31	      const colonIdx = payload.indexOf(':');
32	      const ivHex = payload.slice(0, colonIdx);
33	      const encHex = payload.slice(colonIdx + 1);
34	      const iv = Buffer.from(ivHex, 'hex');
35	      const encrypted = Buffer.from(encHex, 'hex');
36	      const decipher = crypto.createDecipheriv(ALGORITHM, this.key, iv);
37	      return Buffer.concat([decipher.update(encrypted), decipher.final()]).toString('utf8');
38	    } catch {
39	      return ciphertext;
40	    }
41	  }
42	}
