1	import {
2	  Injectable,
3	  BadRequestException,
4	  NotFoundException,
5	  ForbiddenException,
6	} from '@nestjs/common';
7	import { InjectRepository } from '@nestjs/typeorm';
8	import { Repository, DataSource, SelectQueryBuilder } from 'typeorm';
9	import { SavedQuery } from '../database/entities/saved-query.entity';
10	import { PowerQueryDto, QueryFilterItem } from './dto/query.dto';
11	import { EncryptionService } from '../common/encryption/encryption.service';
12	
13	const ENTITY_MAP: Record<string, string> = {
14	  listings: 'Listing',
15	  users: 'User',
16	  conversations: 'Conversation',
17	  settlements: 'Settlement',
18	};
19	
20	const ALLOWED_FIELDS: Record<string, string[]> = {
21	  listings: ['id', 'title', 'breed', 'region', 'priceUsd', 'age', 'rating', 'status', 'createdAt', 'vendorId'],
22	  users: ['id', 'username', 'role', 'isActive', 'createdAt'],
23	  conversations: ['id', 'listingId', 'vendorId', 'isArchived', 'isDisputed', 'createdAt'],
24	  settlements: ['id', 'vendorId', 'month', 'totalCharges', 'taxAmount', 'status', 'createdAt'],
25	};
26	
27	@Injectable()
28	export class QueryService {
29	  constructor(
30	    @InjectRepository(SavedQuery)
31	    private readonly savedQueryRepo: Repository<SavedQuery>,
32	    private readonly dataSource: DataSource,
33	    private readonly encryption: EncryptionService,
34	  ) {}
35	
36	  async execute(
37	    dto: PowerQueryDto,
38	    userId: string,
39	    role: string,
40	  ): Promise<{ items: unknown[]; total: number; page: number; limit: number; totalPages: number }> {
41	    const entityName = ENTITY_MAP[dto.entity];
42	    if (!entityName) throw new BadRequestException(`Unknown entity: ${dto.entity}`);
43	
44	    if (role === 'vendor' && (dto.entity === 'users' || dto.entity === 'conversations')) {
45	      throw new ForbiddenException('Vendors cannot query users or conversations');
46	    }
47	
48	    const allowed = ALLOWED_FIELDS[dto.entity] ?? [];
49	    const repo = this.dataSource.getRepository(entityName);
50	    const alias = 'e';
51	    const qb = repo.createQueryBuilder(alias);
52	
53	    if (role === 'vendor' && dto.entity === 'listings') {
54	      qb.andWhere(`${alias}.vendorId = :userId`, { userId });
55	    }
56	    if (role === 'vendor' && dto.entity === 'settlements') {
57	      qb.andWhere(`${alias}.vendorId = :userId`, { userId });
58	    }
59	
60	    if (dto.filters) {
61	      for (let i = 0; i < dto.filters.length; i++) {
62	        const f = dto.filters[i];
63	        if (!allowed.includes(f.field)) {
64	          throw new BadRequestException(`Field "${f.field}" not allowed for entity "${dto.entity}"`);
65	        }
66	        const paramName = `p${i}`;
67	        this.applyFilter(qb, alias, f, paramName);
68	      }
69	    }
70	
71	    if (dto.sort && allowed.includes(dto.sort.field)) {
72	      qb.orderBy(`${alias}.${dto.sort.field}`, dto.sort.dir.toUpperCase() as 'ASC' | 'DESC');
73	    } else {
74	      qb.orderBy(`${alias}.createdAt`, 'DESC');
75	    }
76	
77	    const page = Math.max(1, dto.page ?? 1);
78	    const limit = Math.min(100, Math.max(1, dto.limit ?? 20));
79	    qb.skip((page - 1) * limit).take(limit);
80	
81	    const [items, total] = await qb.getManyAndCount();
82	
83	    const masked = items.map((item: any) => {
84	      if (dto.entity === 'users' && role !== 'admin') {
85	        const { passwordHash, email, deviceFingerprint, ...safe } = item;
86	        return safe;
87	      }
88	      return item;
89	    });
90	
91	    return {
92	      items: masked,
93	      total,
94	      page,
95	      limit,
96	      totalPages: Math.ceil(total / limit),
97	    };
98	  }
99	
100	  async saveQuery(userId: string, name: string, params: Record<string, unknown>): Promise<SavedQuery> {
101	    const sq = this.savedQueryRepo.create({ userId, name, params });
102	    return this.savedQueryRepo.save(sq);
103	  }
104	
105	  async getSavedQueries(userId: string): Promise<SavedQuery[]> {
106	    return this.savedQueryRepo.find({
107	      where: { userId },
108	      order: { createdAt: 'DESC' },
109	    });
110	  }
111	
112	  async deleteSavedQuery(id: string, userId: string): Promise<void> {
113	    const sq = await this.savedQueryRepo.findOne({ where: { id } });
114	    if (!sq) throw new NotFoundException('Saved query not found');
115	    if (sq.userId !== userId) throw new ForbiddenException('Cannot delete another user\'s saved query');
116	    await this.savedQueryRepo.delete(id);
117	  }
118	
119	  private applyFilter(
120	    qb: SelectQueryBuilder<any>,
121	    alias: string,
122	    filter: QueryFilterItem,
123	    paramName: string,
124	  ): void {
125	    const col = `${alias}.${filter.field}`;
126	    switch (filter.op) {
127	      case 'eq':
128	        qb.andWhere(`${col} = :${paramName}`, { [paramName]: filter.value });
129	        break;
130	      case 'gt':
131	        qb.andWhere(`${col} > :${paramName}`, { [paramName]: filter.value });
132	        break;
133	      case 'lt':
134	        qb.andWhere(`${col} < :${paramName}`, { [paramName]: filter.value });
135	        break;
136	      case 'gte':
137	        qb.andWhere(`${col} >= :${paramName}`, { [paramName]: filter.value });
138	        break;
139	      case 'lte':
140	        qb.andWhere(`${col} <= :${paramName}`, { [paramName]: filter.value });
141	        break;
142	      case 'contains':
143	        qb.andWhere(`${col} ILIKE :${paramName}`, { [paramName]: `%${filter.value}%` });
144	        break;
145	      case 'in':
146	        if (Array.isArray(filter.value)) {
147	          qb.andWhere(`${col} IN (:...${paramName})`, { [paramName]: filter.value });
148	        }
149	        break;
150	    }
151	  }
152	}
