74	  async search(query: SearchListingsDto): Promise<PaginatedResult<Listing>> {
75	    const page = Math.max(1, query.page ?? 1);
76	    const limit = Math.min(100, Math.max(1, query.limit ?? 20));
77	    const skip = (page - 1) * limit;
78	
79	    const correctedQ = query.q ? this.correctTypos(query.q) : undefined;
80	
81	    const qb = this.listingRepo
82	      .createQueryBuilder('l')
83	      .where('l.status = :status', { status: ListingStatus.ACTIVE })
84	      .andWhere('l.deletedAt IS NULL');
85	
86	    if (correctedQ) {
87	      qb.andWhere(
88	        '(l.title ILIKE :q OR l.description ILIKE :q OR l.breed ILIKE :q)',
89	        { q: `%${correctedQ}%` },
90	      );
91	    }
92	    if (query.breed) {
93	      qb.andWhere('LOWER(l.breed) = LOWER(:breed)', { breed: query.breed });
94	    }
95	    if (query.region) {
96	      qb.andWhere('LOWER(l.region) = LOWER(:region)', { region: query.region });
97	    }
98	    if (query.minAge !== undefined) {
99	      qb.andWhere('l.age >= :minAge', { minAge: query.minAge });
100	    }
101	    if (query.maxAge !== undefined) {
102	      qb.andWhere('l.age <= :maxAge', { maxAge: query.maxAge });
103	    }
104	    if (query.minPrice !== undefined) {
105	      qb.andWhere('l.priceUsd >= :minPrice', { minPrice: query.minPrice });
106	    }
107	    if (query.maxPrice !== undefined) {
108	      qb.andWhere('l.priceUsd <= :maxPrice', { maxPrice: query.maxPrice });
109	    }
110	    if (query.minRating !== undefined) {
111	      qb.andWhere('l.rating >= :minRating', { minRating: query.minRating });
112	    }
113	    if (query.maxRating !== undefined) {
114	      qb.andWhere('l.rating <= :maxRating', { maxRating: query.maxRating });
115	    }
116	    if (query.newArrivals) {
117	      const fourteenDaysAgo = new Date(Date.now() - 14 * 24 * 60 * 60 * 1000);
118	      qb.andWhere('l.createdAt >= :since', { since: fourteenDaysAgo });
119	    }
120	
121	    this.applySorting(qb, query.sort);
122	    qb.skip(skip).take(limit);
123	
124	    const [items, total] = await qb.getManyAndCount();
125	
126	    const result: PaginatedResult<Listing> = {
127	      items,
128	      total,
129	      page,
130	      limit,
131	      totalPages: Math.ceil(total / limit),
132	    };
133	
134	    if (total === 0) {
135	      result.fallback = await this.buildFallback(query.breed ?? correctedQ);
136	    }
137	
138	    return result;
139	  }
