141	  async suggest(q: string): Promise<string[]> {
142	    if (!q || q.length < 1) return [];
143	    const corrected = this.correctTypos(q);
144	    const pattern = `%${corrected}%`;
145	
146	    const breeds = await this.listingRepo
147	      .createQueryBuilder('l')
148	      .select('DISTINCT l.breed', 'value')
149	      .where('l.breed ILIKE :pattern', { pattern })
150	      .andWhere('l.status = :status', { status: ListingStatus.ACTIVE })
151	      .andWhere('l.deletedAt IS NULL')
152	      .limit(5)
153	      .getRawMany();
154	
155	    const titles = await this.listingRepo
156	      .createQueryBuilder('l')
157	      .select('l.title', 'value')
158	      .where('l.title ILIKE :pattern', { pattern })
159	      .andWhere('l.status = :status', { status: ListingStatus.ACTIVE })
160	      .andWhere('l.deletedAt IS NULL')
161	      .limit(5)
162	      .getRawMany();
163	
164	    const seen = new Set<string>();
165	    const results: string[] = [];
166	    for (const row of [...breeds, ...titles]) {
167	      const v = row.value as string;
168	      if (!seen.has(v.toLowerCase())) {
169	        seen.add(v.toLowerCase());
170	        results.push(v);
171	      }
172	      if (results.length >= 10) break;
173	    }
174	    return results;
175	  }
