293	  private applySorting(qb: SelectQueryBuilder<Listing>, sort?: string): void {
294	    switch (sort) {
295	      case 'price_asc':
296	        qb.orderBy('l.priceUsd', 'ASC');
297	        break;
298	      case 'price_desc':
299	        qb.orderBy('l.priceUsd', 'DESC');
300	        break;
301	      case 'rating_desc':
302	        qb.orderBy('l.rating', 'DESC');
303	        break;
