311	  private async buildFallback(
312	    breedHint?: string,
313	  ): Promise<{ similarBreed: Listing[]; trending: Listing[] }> {
314	    let similarBreed: Listing[] = [];
315	    if (breedHint) {
316	      similarBreed = await this.listingRepo
317	        .createQueryBuilder('l')
318	        .where('l.status = :status', { status: ListingStatus.ACTIVE })
319	        .andWhere('l.deletedAt IS NULL')
320	        .andWhere('l.breed ILIKE :breed', { breed: `%${breedHint}%` })
321	        .orderBy('l.rating', 'DESC')
322	        .limit(5)
323	        .getMany();
324	    }
325	
326	    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
327	    const trending = await this.listingRepo
328	      .createQueryBuilder('l')
329	      .where('l.status = :status', { status: ListingStatus.ACTIVE })
330	      .andWhere('l.deletedAt IS NULL')
331	      .andWhere('l.createdAt >= :since', { since: sevenDaysAgo })
332	      .orderBy('l.rating', 'DESC')
333	      .limit(5)
334	      .getMany();
335	
336	    return { similarBreed, trending };
337	  }
