339	  private async checkSensitiveWords(
340	    title: string,
341	    description: string,
342	  ): Promise<{ flagged: boolean; matchedWords: string[] }> {
343	    const words = await this.wordRepo.find();
344	    const combined = `${title} ${description}`.toLowerCase();
345	    const matched = words.filter((sw) => combined.includes(sw.word.toLowerCase()));
346	    return { flagged: matched.length > 0, matchedWords: matched.map((w) => w.word) };
347	  }
