349	  private async enforceRateLimit(vendorId: string): Promise<void> {
350	    const windowStart = new Date(Date.now() - RATE_LIMIT_WINDOW_MS);
351	    const count = await this.rateLimitRepo.count({
352	      where: {
353	        userId: vendorId,
354	        action: 'create_listing',
355	        createdAt: MoreThanOrEqual(windowStart),
356	      },
357	    });
358	    if (count >= RATE_LIMIT_MAX) {
359	      throw new HttpException('Rate limit exceeded: max 30 listings per hour', HttpStatus.TOO_MANY_REQUESTS);
360	    }
361	  }
362	
363	  private async detectDuplicate(vendorId: string, title: string): Promise<string | undefined> {
364	    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
365	    const recent = await this.listingRepo
366	      .createQueryBuilder('l')
367	      .where('l.vendorId = :vendorId', { vendorId })
368	      .andWhere('l.createdAt >= :since', { since: oneDayAgo })
369	      .andWhere('l.deletedAt IS NULL')
370	      .getMany();
371	
372	    const inputTokens = this.tokenize(title);
373	    if (inputTokens.length === 0) return undefined;
374	
375	    for (const listing of recent) {
376	      const existingTokens = this.tokenize(listing.title);
377	      if (existingTokens.length === 0) continue;
378	      const intersection = inputTokens.filter((t) => existingTokens.includes(t));
379	      const overlap = intersection.length / Math.max(inputTokens.length, existingTokens.length);
380	      if (overlap >= 0.8) {
381	        return `Near-duplicate detected: similar to "${listing.title}" (${Math.round(overlap * 100)}% overlap)`;
382	      }
383	    }
384	    return undefined;
385	  }
386	
387	  private tokenize(text: string): string[] {
388	    return text.toLowerCase().split(/\s+/).filter((w) => w.length > 2);
389	  }
