1	import {
2	  Injectable,
3	  NotFoundException,
4	  BadRequestException,
5	  ForbiddenException,
6	} from '@nestjs/common';
7	import { InjectRepository } from '@nestjs/typeorm';
8	import { Repository } from 'typeorm';
9	import { Settlement, SettlementStatus } from '../database/entities/settlement.entity';
10	import { Listing } from '../database/entities/listing.entity';
11	import { User } from '../database/entities/user.entity';
12	import { AuditService } from '../audit/audit.service';
13	import { FreightService } from './freight.service';
14	import { SettlementFiltersDto } from './dto/settlement.dto';
15	import { EncryptionService } from '../common/encryption/encryption.service';
16	
17	@Injectable()
18	export class SettlementsService {
19	  constructor(
20	    @InjectRepository(Settlement)
21	    private readonly settlementRepo: Repository<Settlement>,
22	    @InjectRepository(Listing)
23	    private readonly listingRepo: Repository<Listing>,
24	    @InjectRepository(User)
25	    private readonly userRepo: Repository<User>,
26	    private readonly auditService: AuditService,
27	    private readonly freightService: FreightService,
28	    private readonly encryption: EncryptionService,
29	  ) {}
30	
31	  async findAll(
32	    userId: string,
33	    role: string,
34	    filters: SettlementFiltersDto,
35	  ): Promise<Settlement[]> {
36	    const qb = this.settlementRepo.createQueryBuilder('s');
37	
38	    if (role === 'vendor') {
39	      qb.where('s.vendorId = :userId', { userId });
40	    }
41	    if (filters.month) {
42	      qb.andWhere('s.month = :month', { month: filters.month });
43	    }
44	    if (filters.status) {
45	      qb.andWhere('s.status = :status', { status: filters.status });
46	    }
47	
48	    return qb.orderBy('s.createdAt', 'DESC').getMany();
49	  }
50	
51	  async findOne(id: string, userId: string, role: string): Promise<{
52	    settlement: Settlement;
53	    variance: { expected: number; actual: number; variance: number; variancePercent: number };
54	  }> {
55	    const settlement = await this.settlementRepo.findOne({ where: { id } });
56	    if (!settlement) throw new NotFoundException('Settlement not found');
57	    if (role === 'vendor' && settlement.vendorId !== userId) {
58	      throw new ForbiddenException('Access denied to this settlement');
59	    }
60	
61	    const expected = Number(settlement.totalCharges);
62	    const actual = expected;
63	    const variance = actual - expected;
64	    const variancePercent = expected > 0 ? (variance / expected) * 100 : 0;
65	
66	    return {
67	      settlement,
68	      variance: {
69	        expected: round(expected),
70	        actual: round(actual),
71	        variance: round(variance),
72	        variancePercent: round(variancePercent),
73	      },
74	    };
75	  }
76	
77	  async generateMonthly(month: string, actorId: string): Promise<Settlement[]> {
78	    const vendors = await this.userRepo.find({ where: { role: 'vendor' as any, isActive: true } });
79	    const results: Settlement[] = [];
80	
81	    for (const vendor of vendors) {
82	      const existing = await this.settlementRepo.findOne({
83	        where: { vendorId: vendor.id, month },
84	      });
85	      if (existing) continue;
86	
87	      const listings = await this.listingRepo
88	        .createQueryBuilder('l')
89	        .where('l.vendorId = :vendorId', { vendorId: vendor.id })
90	        .andWhere("to_char(l.\"createdAt\", 'YYYY-MM') = :month", { month })
91	        .getMany();
92	
93	      let totalCharges = 0;
94	      for (const listing of listings) {
95	        const freight = this.freightService.calculate({
96	          distanceMiles: 150,
97	          weightLbs: Number(listing.age) * 2 + 5,
98	          dimWeightLbs: 10,
99	          isOversized: false,
100	          isWeekend: false,
101	        });
102	        totalCharges += freight.total;
103	      }
104	
105	      const taxAmount = round(totalCharges * 0.085);
106	
107	      const settlement = this.settlementRepo.create({
108	        vendorId: vendor.id,
109	        month,
110	        totalCharges,
111	        taxAmount,
112	        status: SettlementStatus.PENDING,
113	        data: { listingCount: listings.length },
114	      });
115	      const saved = await this.settlementRepo.save(settlement);
116	      results.push(saved);
117	
118	      await this.auditService.log({
119	        action: 'settlement.generate',
120	        actorId,
