  async expireJob(job: ExportJob): Promise<void> {
    if (job.filePath) {
      const result = safeDeleteFile(job.filePath);
      if (result.deleted) {
        logger.info(`Deleted export file: ${job.filePath}`, { context: 'ExportExpiry' });
