1	import { Injectable } from '@nestjs/common';
2	import { InjectRepository } from '@nestjs/typeorm';
3	import { Repository, MoreThanOrEqual } from 'typeorm';
4	import { User } from '../database/entities/user.entity';
5	import { Listing } from '../database/entities/listing.entity';
6	import { RateLimitEvent } from '../database/entities/rate-limit-event.entity';
7	import { AuditService } from '../audit/audit.service';
8	import { EncryptionService } from '../common/encryption/encryption.service';
9	import { logger } from '../common/logger/winston.logger';
10	
11	export interface RiskFlag {
12	  riskFlag: string;
13	  detail: string;
14	}
15	
16	@Injectable()
17	export class RiskService {
18	  constructor(
19	    @InjectRepository(User)
20	    private readonly userRepo: Repository<User>,
21	    @InjectRepository(Listing)
22	    private readonly listingRepo: Repository<Listing>,
23	    private readonly auditService: AuditService,
24	    private readonly encryption: EncryptionService,
25	  ) {}
26	
27	  async assessListingCreation(
28	    vendorId: string,
29	    breed: string,
30	    deviceFingerprint?: string,
31	    ip?: string,
32	  ): Promise<RiskFlag[]> {
33	    const flags: RiskFlag[] = [];
34	
35	    if (deviceFingerprint) {
36	      const multiAccountFlag = await this.checkMultiAccountDevice(
37	        vendorId,
38	        deviceFingerprint,
39	      );
40	      if (multiAccountFlag) flags.push(multiAccountFlag);
41	    }
42	
43	    if (ip) {
44	      const ipFlag = await this.checkIpRisk(ip);
45	      if (ipFlag) flags.push(ipFlag);
46	    }
47	
48	    const repostFlag = await this.checkFrequentRepost(vendorId, breed);
49	    if (repostFlag) flags.push(repostFlag);
50	
51	    for (const flag of flags) {
52	      await this.auditService.log({
53	        action: 'RISK_FLAG',
54	        actorId: vendorId,
55	        entityType: 'listing',
56	        deviceFingerprint,
57	        ip,
58	        after: { flag: flag.riskFlag, detail: flag.detail } as unknown as Record<string, unknown>,
59	      });
60	      logger.warn(`Risk flag: ${flag.riskFlag} for user ${vendorId}`, {
61	        context: 'RiskService',
62	      });
63	    }
64	
65	    return flags;
66	  }
67	
68	  async assessConversationCreation(
69	    userId: string,
70	    deviceFingerprint?: string,
71	    ip?: string,
72	  ): Promise<RiskFlag[]> {
73	    const flags: RiskFlag[] = [];
74	
75	    if (deviceFingerprint) {
76	      const multiAccountFlag = await this.checkMultiAccountDevice(userId, deviceFingerprint);
77	      if (multiAccountFlag) flags.push(multiAccountFlag);
78	    }
79	
80	    if (ip) {
81	      const ipFlag = await this.checkIpRisk(ip);
82	      if (ipFlag) flags.push(ipFlag);
83	    }
84	
85	    for (const flag of flags) {
86	      await this.auditService.log({
87	        action: 'RISK_FLAG',
88	        actorId: userId,
89	        entityType: 'conversation',
90	        deviceFingerprint,
91	        ip,
92	        after: { flag: flag.riskFlag, detail: flag.detail } as unknown as Record<string, unknown>,
93	      });
94	    }
95	
96	    return flags;
97	  }
98	
99	  private async checkMultiAccountDevice(
100	    userId: string,
101	    deviceFingerprint: string,
102	  ): Promise<RiskFlag | null> {
103	    const users = await this.userRepo.find();
104	    let matchCount = 0;
105	
106	    for (const user of users) {
107	      if (user.id === userId) continue;
108	      if (!user.deviceFingerprint) continue;
109	      try {
110	        const decrypted = this.encryption.decrypt(user.deviceFingerprint);
111	        if (decrypted === deviceFingerprint) matchCount++;
112	      } catch {
113	        continue;
114	      }
115	    }
116	
117	    if (matchCount >= 2) {
118	      return {
119	        riskFlag: 'multi_account_device',
120	        detail: `Device fingerprint found on ${matchCount + 1} accounts`,
121	      };
122	    }
123	    return null;
124	  }
125	
126	  private async checkIpRisk(ip: string): Promise<RiskFlag | null> {
127	    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
128	    const recentUsers = await this.userRepo
129	      .createQueryBuilder('u')
130	      .where('u.lastIp = :ip', { ip })
131	      .andWhere('u.createdAt >= :since', { since: oneDayAgo })
132	      .getCount();
133	
134	    if (recentUsers > 5) {
