30	@Injectable()
31	export class AuditService {
32	  constructor(
33	    @InjectRepository(AuditLog)
34	    private readonly auditRepo: Repository<AuditLog>,
35	  ) {}
36	
37	  async log(input: AuditLogInput): Promise<AuditLog> {
38	    const latest = await this.auditRepo.findOne({
39	      where: {},
40	      order: { createdAt: 'DESC' },
41	    });
42	
43	    const prevHash = latest?.hash ?? null;
44	    const ts = new Date().toISOString();
45	    const hashPayload = (prevHash ?? '') + JSON.stringify({
46	      action: input.action,
47	      actorId: input.actorId,
48	      entityType: input.entityType,
49	      entityId: input.entityId ?? null,
50	      before: input.before ?? null,
51	      after: input.after ?? null,
52	      ts,
53	    });
54	    const hash = crypto.createHash('sha256').update(hashPayload).digest('hex');
55	
56	    const entry = this.auditRepo.create({
57	      action: input.action,
58	      actorId: input.actorId,
59	      entityType: input.entityType,
60	      entityId: input.entityId ?? null,
61	      before: input.before ?? null,
62	      after: input.after ?? null,
63	      deviceFingerprint: input.deviceFingerprint ?? null,
64	      ip: input.ip ?? null,
65	      hash,
66	      prevHash,
67	      createdAt: new Date(ts),
68	    });
69	
70	    return this.auditRepo.save(entry);
71	  }
72	
73	  async findAll(
74	    page = 1,
75	    limit = 50,
76	  ): Promise<{ items: AuditLog[]; total: number }> {
77	    const [items, total] = await this.auditRepo.findAndCount({
78	      order: { createdAt: 'DESC' },
79	      skip: (page - 1) * limit,
80	      take: limit,
81	    });
82	    return { items, total };
83	  }
84	
85	  async findAllFiltered(
86	    filters: AuditFilters,
87	  ): Promise<{ items: (AuditLog & { actorUsername?: string })[]; total: number }> {
88	    const page = Math.max(1, filters.page ?? 1);
89	    const limit = Math.min(200, Math.max(1, filters.limit ?? 50));
90	
91	    const qb = this.auditRepo
92	      .createQueryBuilder('a')
93	      .orderBy('a.createdAt', 'DESC');
94	
95	    if (filters.actorId) {
96	      qb.andWhere('a.actorId = :actorId', { actorId: filters.actorId });
97	    }
98	    if (filters.entityType) {
99	      qb.andWhere('a.entityType = :entityType', { entityType: filters.entityType });
100	    }
101	    if (filters.action) {
102	      qb.andWhere('a.action ILIKE :action', { action: `%${filters.action}%` });
103	    }
104	    if (filters.startDate) {
105	      qb.andWhere('a.createdAt >= :startDate', { startDate: new Date(filters.startDate) });
106	    }
107	    if (filters.endDate) {
108	      qb.andWhere('a.createdAt <= :endDate', { endDate: new Date(filters.endDate) });
109	    }
110	    if (filters.keyword) {
111	      qb.andWhere(
112	        '(CAST(a.before AS text) ILIKE :kw OR CAST(a.after AS text) ILIKE :kw)',
113	        { kw: `%${filters.keyword}%` },
114	      );
115	    }
116	
117	    qb.skip((page - 1) * limit).take(limit);
118	
119	    const [items, total] = await qb.getManyAndCount();
120	
121	    const actorIds = [...new Set(items.map((i) => i.actorId).filter(Boolean))];
122	    const userMap: Record<string, string> = {};
123	    if (actorIds.length > 0) {
124	      const userRepo = this.auditRepo.manager.getRepository(User);
125	      const users = await userRepo
126	        .createQueryBuilder('u')
127	        .where('u.id IN (:...ids)', { ids: actorIds })
128	        .getMany();
129	      for (const u of users) {
130	        userMap[u.id] = u.username;
131	      }
132	    }
133	
134	    const enriched = items.map((item) => ({
135	      ...item,
136	      actorUsername: userMap[item.actorId] ?? 'unknown',
137	    }));
138	
139	    return { items: enriched, total };
140	  }
141	
142	  async verifyEntry(id: string): Promise<{ valid: boolean; entry: AuditLog }> {
143	    const entry = await this.auditRepo.findOne({ where: { id } });
144	    if (!entry) {
145	      throw new Error('Audit entry not found');
146	    }
147	
148	    const recomputedPayload = (entry.prevHash ?? '') + JSON.stringify({
149	      action: entry.action,
150	      actorId: entry.actorId,
151	      entityType: entry.entityType,
152	      entityId: entry.entityId ?? null,
153	      before: entry.before ?? null,
154	      after: entry.after ?? null,
155	      ts: entry.createdAt.toISOString(),
156	    });
157	    const recomputedHash = crypto
158	      .createHash('sha256')
159	      .update(recomputedPayload)
160	      .digest('hex');
161	
162	    return {
163	      valid: recomputedHash === entry.hash,
164	      entry,
165	    };
166	  }
167	}
