95	    if (filters.actorId) {
96	      qb.andWhere('a.actorId = :actorId', { actorId: filters.actorId });
97	    }
98	    if (filters.entityType) {
99	      qb.andWhere('a.entityType = :entityType', { entityType: filters.entityType });
100	    }
101	    if (filters.action) {
102	      qb.andWhere('a.action ILIKE :action', { action: `%${filters.action}%` });
103	    }
104	    if (filters.startDate) {
105	      qb.andWhere('a.createdAt >= :startDate', { startDate: new Date(filters.startDate) });
106	    }
107	    if (filters.endDate) {
108	      qb.andWhere('a.createdAt <= :endDate', { endDate: new Date(filters.endDate) });
109	    }
110	    if (filters.keyword) {
111	      qb.andWhere(
112	        '(CAST(a.before AS text) ILIKE :kw OR CAST(a.after AS text) ILIKE :kw)',
113	        { kw: `%${filters.keyword}%` },
114	      );
115	    }
116	
117	    qb.skip((page - 1) * limit).take(limit);
118	
119	    const [items, total] = await qb.getManyAndCount();
120	
121	    const actorIds = [...new Set(items.map((i) => i.actorId).filter(Boolean))];
