123	    if (actorIds.length > 0) {
124	      const userRepo = this.auditRepo.manager.getRepository(User);
125	      const users = await userRepo
126	        .createQueryBuilder('u')
127	        .where('u.id IN (:...ids)', { ids: actorIds })
128	        .getMany();
129	      for (const u of users) {
130	        userMap[u.id] = u.username;
131	      }
132	    }
