142	  async verifyEntry(id: string): Promise<{ valid: boolean; entry: AuditLog }> {
143	    const entry = await this.auditRepo.findOne({ where: { id } });
144	    if (!entry) {
145	      throw new Error('Audit entry not found');
146	    }
147	
148	    const recomputedPayload = (entry.prevHash ?? '') + JSON.stringify({
149	      action: entry.action,
150	      actorId: entry.actorId,
151	      entityType: entry.entityType,
152	      entityId: entry.entityId ?? null,
153	      before: entry.before ?? null,
154	      after: entry.after ?? null,
155	      ts: entry.createdAt.toISOString(),
156	    });
157	    const recomputedHash = crypto
158	      .createHash('sha256')
159	      .update(recomputedPayload)
160	      .digest('hex');
161	
162	    return {
163	      valid: recomputedHash === entry.hash,
164	      entry,
165	    };
