1	import * as crypto from 'crypto';
2	
3	interface AuditEntry {
4	  action: string;
5	  actorId: string;
6	  entityType: string;
7	  entityId: string | null;
8	  before: Record<string, unknown> | null;
9	  after: Record<string, unknown> | null;
10	  hash: string;
11	  prevHash: string | null;
12	  createdAt: Date;
13	}
14	
15	function computeHash(entry: Omit<AuditEntry, 'hash'>, prevHash: string | null): string {
16	  const payload = (prevHash ?? '') + JSON.stringify({
17	    action: entry.action,
18	    actorId: entry.actorId,
19	    entityType: entry.entityType,
20	    entityId: entry.entityId ?? null,
21	    before: entry.before ?? null,
22	    after: entry.after ?? null,
23	    ts: entry.createdAt.toISOString(),
24	  });
25	  return crypto.createHash('sha256').update(payload).digest('hex');
26	}
27	
28	function verifyEntry(entry: AuditEntry): boolean {
29	  const recomputed = computeHash(entry, entry.prevHash);
30	  return recomputed === entry.hash;
31	}
32	
33	function createEntry(
34	  action: string,
35	  prevHash: string | null,
36	  time: Date,
37	): AuditEntry {
38	  const base = {
39	    action,
40	    actorId: 'user-1',
41	    entityType: 'listing',
42	    entityId: 'listing-1',
43	    before: null,
44	    after: { title: 'test' },
45	    prevHash,
46	    createdAt: time,
47	  };
48	  const hash = computeHash(base, prevHash);
49	  return { ...base, hash };
50	}
51	
52	describe('AuditHashChain', () => {
53	  it('first entry hash computed from null prevHash', () => {
54	    const entry = createEntry('create', null, new Date('2024-01-01T00:00:00Z'));
55	    expect(entry.prevHash).toBeNull();
56	    expect(entry.hash).toHaveLength(64);
57	    expect(verifyEntry(entry)).toBe(true);
58	  });
59	
60	  it('chain: entry N prevHash = entry N-1 hash', () => {
61	    const entry1 = createEntry('create', null, new Date('2024-01-01T00:00:00Z'));
62	    const entry2 = createEntry('update', entry1.hash, new Date('2024-01-01T01:00:00Z'));
63	    const entry3 = createEntry('delete', entry2.hash, new Date('2024-01-01T02:00:00Z'));
64	
65	    expect(entry2.prevHash).toBe(entry1.hash);
66	    expect(entry3.prevHash).toBe(entry2.hash);
67	    expect(verifyEntry(entry1)).toBe(true);
68	    expect(verifyEntry(entry2)).toBe(true);
69	    expect(verifyEntry(entry3)).toBe(true);
70	  });
71	
72	  it('tamper detection: modifying content breaks hash', () => {
73	    const entry = createEntry('create', null, new Date('2024-01-01T00:00:00Z'));
74	    expect(verifyEntry(entry)).toBe(true);
75	
76	    const tampered = { ...entry, action: 'TAMPERED' };
77	    expect(verifyEntry(tampered)).toBe(false);
78	  });
79	
80	  it('tamper detection: modifying after data breaks hash', () => {
81	    const entry = createEntry('create', null, new Date('2024-01-01T00:00:00Z'));
82	    const tampered = { ...entry, after: { title: 'hacked' } };
83	    expect(verifyEntry(tampered)).toBe(false);
84	  });
85	
86	  it('tamper detection: modifying prevHash breaks hash', () => {
87	    const entry1 = createEntry('create', null, new Date('2024-01-01T00:00:00Z'));
88	    const entry2 = createEntry('update', entry1.hash, new Date('2024-01-01T01:00:00Z'));
89	
90	    const tampered2 = { ...entry2, prevHash: 'fakehash' };
91	    expect(verifyEntry(tampered2)).toBe(false);
92	  });
93	
94	  it('different timestamps produce different hashes', () => {
95	    const entry1 = createEntry('create', null, new Date('2024-01-01T00:00:00Z'));
96	    const entry2 = createEntry('create', null, new Date('2024-01-01T00:00:01Z'));
97	    expect(entry1.hash).not.toBe(entry2.hash);
98	  });
99	});
