1	import {
2	  Injectable,
3	  NotFoundException,
4	  OnModuleInit,
5	  OnModuleDestroy,
6	  HttpException,
7	  HttpStatus,
8	} from '@nestjs/common';
9	import { InjectRepository } from '@nestjs/typeorm';
10	import { Repository, In, LessThan, DataSource } from 'typeorm';
11	import * as fs from 'fs';
12	import * as path from 'path';
13	import { ExportJob, ExportJobStatus } from '../database/entities/export-job.entity';
14	import { CreateExportJobDto } from './dto/export.dto';
15	import { EncryptionService } from '../common/encryption/encryption.service';
16	import { logger } from '../common/logger/winston.logger';
17	import { safeDeleteFile } from './export-file.util';
18	
19	const MAX_CONCURRENT = 2;
20	const EXPIRY_DAYS = 7;
21	const EXPORT_DIR = '/tmp/exports';
22	const POLL_INTERVAL_MS = 5000;
23	
24	@Injectable()
25	export class ExportsService implements OnModuleInit, OnModuleDestroy {
26	  private pollTimer: ReturnType<typeof setInterval> | null = null;
27	
28	  constructor(
29	    @InjectRepository(ExportJob)
30	    private readonly exportRepo: Repository<ExportJob>,
31	    private readonly dataSource: DataSource,
32	    private readonly encryption: EncryptionService,
33	  ) {}
34	
35	  onModuleInit() {
36	    if (!fs.existsSync(EXPORT_DIR)) {
37	      fs.mkdirSync(EXPORT_DIR, { recursive: true });
38	    }
39	    this.pollTimer = setInterval(() => this.processPendingJobs(), POLL_INTERVAL_MS);
40	  }
41	
42	  onModuleDestroy() {
43	    if (this.pollTimer) clearInterval(this.pollTimer);
44	  }
45	
46	  async createJob(requesterId: string, dto: CreateExportJobDto): Promise<ExportJob> {
47	    const expiresAt = new Date();
48	    expiresAt.setDate(expiresAt.getDate() + EXPIRY_DAYS);
49	
50	    const job = this.exportRepo.create({
51	      requesterId,
52	      status: ExportJobStatus.QUEUED,
53	      params: { type: dto.type, filters: dto.filters ?? {} },
54	      expiresAt,
55	    });
56	
57	    return this.exportRepo.save(job);
58	  }
59	
60	  async findAll(requesterId: string, role: string): Promise<ExportJob[]> {
61	    if (role === 'admin') {
62	      return this.exportRepo.find({ order: { createdAt: 'DESC' } });
63	    }
64	    return this.exportRepo.find({
65	      where: { requesterId },
66	      order: { createdAt: 'DESC' },
67	    });
68	  }
69	
70	  async getJobStatus(id: string, requesterId: string, role: string): Promise<ExportJob> {
71	    const job = await this.exportRepo.findOne({ where: { id } });
72	    if (!job) throw new NotFoundException('Export job not found');
73	    if (role !== 'admin' && job.requesterId !== requesterId) {
74	      throw new NotFoundException('Export job not found');
75	    }
76	    return job;
77	  }
78	
79	  async downloadFile(
80	    id: string,
81	    requesterId: string,
82	    role: string,
83	  ): Promise<{ filePath: string; fileName: string }> {
84	    const job = await this.getJobStatus(id, requesterId, role);
85	
86	    if (job.status === ExportJobStatus.EXPIRED) {
87	      throw new NotFoundException('Export file has expired');
88	    }
89	    if (job.status !== ExportJobStatus.DONE || !job.filePath) {
90	      throw new HttpException('Export is still processing', HttpStatus.ACCEPTED);
91	    }
92	    if (job.expiresAt && new Date() > new Date(job.expiresAt)) {
93	      await this.expireJob(job);
94	      throw new NotFoundException('Export file has expired');
95	    }
96	
97	    return { filePath: job.filePath, fileName: `export-${id}.csv` };
98	  }
99	
100	  private async processPendingJobs(): Promise<void> {
101	    try {
102	      await this.expireOldJobs();
103	
104	      const runningCount = await this.exportRepo.count({
105	        where: { status: ExportJobStatus.RUNNING },
106	      });
107	      if (runningCount >= MAX_CONCURRENT) return;
108	
109	      const slotsAvailable = MAX_CONCURRENT - runningCount;
110	      const queued = await this.exportRepo.find({
111	        where: { status: ExportJobStatus.QUEUED },
112	        order: { createdAt: 'ASC' },
113	        take: slotsAvailable,
114	      });
115	
116	      for (const job of queued) {
