250	  private async expireOldJobs(): Promise<void> {
251	    const now = new Date();
252	    const toExpire = await this.exportRepo.find({
253	      where: { status: ExportJobStatus.DONE, expiresAt: LessThan(now) },
254	    });
255	    for (const job of toExpire) {
256	      await this.expireJob(job).catch((err: unknown) => {
