1	import { useState, useRef } from 'react';
2	import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
3	import { conversationsApi, type Message, type CannedResponse } from '../api';
4	import { useAuthStore } from '../store/auth.store';
5	import { toast } from '../components/Toaster';
6	import PageHeader from '../components/PageHeader';
7	import { cn, formatDateTime, getErrorMessage } from '../lib/utils';
8	
9	export default function Conversations() {
10	  const { user, role } = useAuthStore();
11	  const qc = useQueryClient();
12	  const [activeId, setActiveId] = useState<string | null>(null);
13	  const [input, setInput] = useState('');
14	  const [isInternal, setIsInternal] = useState(false);
15	  const [keyword, setKeyword] = useState('');
16	  const [showArchived, setShowArchived] = useState(false);
17	
18	  const { data: convs, isLoading } = useQuery({
19	    queryKey: ['conversations', keyword, showArchived],
20	    queryFn: () => conversationsApi.getAll({ keyword: keyword || undefined, archived: showArchived || undefined }),
21	  });
22	
23	  const { data: activeConv, isLoading: msgsLoading } = useQuery({
24	    queryKey: ['conversation', activeId],
25	    queryFn: () => conversationsApi.getOne(activeId!),
26	    enabled: !!activeId,
27	    refetchInterval: 5000,
28	  });
29	
30	  const { data: cannedResponses } = useQuery({
31	    queryKey: ['canned-responses'],
32	    queryFn: () => conversationsApi.getCannedResponses(),
33	  });
34	
35	  const sendMutation = useMutation({
36	    mutationFn: (content: string) =>
37	      conversationsApi.sendMessage(activeId!, { type: 'text', content, isInternal }),
38	    onSuccess: () => {
39	      setInput('');
40	      setIsInternal(false);
41	      qc.invalidateQueries({ queryKey: ['conversation', activeId] });
42	    },
43	    onError: (err) => toast(getErrorMessage(err), 'error'),
44	  });
45	
46	  const voiceInputRef = useRef<HTMLInputElement>(null);
47	
48	  const voiceMutation = useMutation({
49	    mutationFn: (file: File) => conversationsApi.uploadVoice(activeId!, file),
50	    onSuccess: () => {
51	      qc.invalidateQueries({ queryKey: ['conversation', activeId] });
52	      toast('Voice message sent');
53	    },
54	    onError: (err) => toast(getErrorMessage(err), 'error'),
55	  });
56	
57	  const archiveMutation = useMutation({
58	    mutationFn: () => conversationsApi.archive(activeId!),
59	    onSuccess: () => {
60	      toast('Conversation archived');
61	      qc.invalidateQueries({ queryKey: ['conversations'] });
62	      setActiveId(null);
63	    },
64	    onError: (err) => toast(getErrorMessage(err), 'error'),
65	  });
66	
67	  const messages = activeConv?.messages ?? [];
68	
69	  return (
70	    <div className="h-[calc(100vh-8rem)]">
71	      <PageHeader title="Conversations" />
72	      <div className="flex h-[calc(100%-3rem)] gap-4">
73	        {/* List */}
74	        <aside className="w-72 flex-shrink-0 flex flex-col bg-white rounded-xl border border-gray-200 overflow-hidden">
75	          <div className="p-3 border-b border-gray-100 space-y-2">
76	            <input
77	              value={keyword}
78	              onChange={(e) => setKeyword(e.target.value)}
79	              placeholder="Search conversations..."
80	              className="w-full border border-gray-300 rounded-lg px-3 py-2 text-sm"
81	            />
82	            <label className="flex items-center gap-2 text-xs text-gray-500">
83	              <input
84	                type="checkbox"
85	                checked={showArchived}
86	                onChange={(e) => setShowArchived(e.target.checked)}
87	                className="rounded"
88	              />
89	              Show archived
90	            </label>
91	          </div>
92	          <div className="flex-1 overflow-y-auto">
93	            {isLoading ? (
94	              <div className="p-3 space-y-2">{Array.from({ length: 4 }).map((_, i) => <div key={i} className="h-14 skeleton" />)}</div>
95	            ) : convs?.length === 0 ? (
96	              <p className="text-sm text-gray-400 text-center py-8">No conversations</p>
97	            ) : (
98	              convs?.map((c) => (
99	                <button
100	                  key={c.id}
101	                  onClick={() => setActiveId(c.id)}
102	                  className={cn(
103	                    'w-full text-left p-3 border-b border-gray-50 hover:bg-gray-50 transition-colors',
104	                    activeId === c.id && 'bg-blue-50 border-l-2 border-l-[#1a56db]',
105	                  )}
106	                >
107	                  <p className="text-sm font-medium text-gray-900 truncate">
108	                    {c.listing?.title ?? `Listing #${c.listingId.slice(0, 8)}`}
109	                  </p>
110	                  <p className="text-xs text-gray-400 mt-0.5">{formatDateTime(c.createdAt)}</p>
111	                  {c.isArchived && <span className="text-[10px] text-gray-400 bg-gray-100 px-1.5 py-0.5 rounded">archived</span>}
112	                </button>
113	              ))
114	            )}
115	          </div>
116	        </aside>
117	
118	        {/* Chat */}
119	        <div className="flex-1 flex flex-col bg-white rounded-xl border border-gray-200 overflow-hidden">
120	          {!activeId ? (
121	            <div className="flex-1 flex items-center justify-center text-gray-400 text-sm">
122	              Select a conversation
123	            </div>
124	          ) : (
125	            <>
126	              <div className="px-4 py-3 border-b border-gray-100 flex items-center justify-between">
127	                <div>
128	                  <p className="font-semibold text-sm text-gray-900">
129	                    {activeConv?.conversation.listing?.title ?? 'Conversation'}
130	                  </p>
131	                </div>
132	                {(role === 'vendor' || role === 'admin') && (
133	                  <button
134	                    onClick={() => archiveMutation.mutate()}
135	                    className="text-xs text-gray-500 hover:text-[#f05252] border border-gray-200 px-3 py-1 rounded-lg"
136	                  >
137	                    Archive
138	                  </button>
139	                )}
140	              </div>
141	
142	              <div className="flex-1 overflow-y-auto p-4 space-y-3">
143	                {msgsLoading && <div className="space-y-2">{Array.from({ length: 3 }).map((_, i) => <div key={i} className="h-10 skeleton" />)}</div>}
144	                {messages.map((m: Message) => (
145	                  <div
146	                    key={m.id}
147	                    className={cn(
148	                      'max-w-[75%] rounded-xl px-4 py-2.5 text-sm',
149	                      m.isInternal
150	                        ? 'bg-yellow-50 border border-yellow-200 text-yellow-900 ml-auto'
151	                        : m.senderId === user?.id
152	                          ? 'bg-[#1a56db] text-white ml-auto'
153	                          : 'bg-gray-100 text-gray-900',
154	                    )}
155	                  >
156	                    {m.isInternal && <span className="text-[10px] font-semibold text-yellow-600 block mb-1">🔒 Internal Note</span>}
157	                    {m.type === 'voice' && m.audioUrl ? (
158	                      <audio controls src={m.audioUrl} className="max-w-full" />
159	                    ) : (
160	                      <p>{m.content}</p>
161	                    )}
162	                    <p className={cn('text-[10px] mt-1', m.senderId === user?.id ? 'text-white/60' : 'text-gray-400')}>
163	                      {formatDateTime(m.createdAt)}
164	                    </p>
165	                  </div>
166	                ))}
167	              </div>
168	
169	              <div className="p-3 border-t border-gray-100 space-y-2">
170	                {(role === 'vendor' || role === 'admin') && (
171	                  <div className="flex items-center gap-2">
172	                    <label className="flex items-center gap-1.5 text-xs text-gray-500">
173	                      <input type="checkbox" checked={isInternal} onChange={(e) => setIsInternal(e.target.checked)} className="rounded" />
174	                      Internal note
175	                    </label>
176	                    {cannedResponses && cannedResponses.length > 0 && (
177	                      <select
178	                        onChange={(e) => { if (e.target.value) setInput(e.target.value); e.target.value = ''; }}
179	                        className="text-xs border border-gray-200 rounded px-2 py-1"
180	                      >
181	                        <option value="">Insert canned response...</option>
182	                        {cannedResponses.map((cr: CannedResponse) => (
183	                          <option key={cr.id} value={cr.body}>{cr.title}</option>
184	                        ))}
185	                      </select>
186	                    )}
187	                  </div>
188	                )}
189	                <div className="flex gap-2">
190	                  <textarea
191	                    value={input}
192	                    onChange={(e) => setInput(e.target.value)}
193	                    onKeyDown={(e) => {
194	                      if (e.key === 'Enter' && !e.shiftKey && input.trim()) {
195	                        e.preventDefault();
196	                        sendMutation.mutate(input.trim());
197	                      }
198	                    }}
199	                    placeholder={isInternal ? 'Add internal note...' : 'Type a message...'}
200	                    rows={2}
201	                    className={cn(
202	                      'flex-1 border rounded-lg px-3 py-2 text-sm resize-none',
203	                      isInternal ? 'border-yellow-300 bg-yellow-50' : 'border-gray-300',
204	                    )}
205	                  />
206	                  <button
207	                    onClick={() => { if (input.trim()) sendMutation.mutate(input.trim()); }}
208	                    disabled={sendMutation.isPending || !input.trim()}
209	                    className="bg-[#1a56db] text-white px-4 rounded-lg text-sm font-medium disabled:opacity-60 self-end h-10"
210	                  >
211	                    Send
212	                  </button>
213	                  <input
214	                    ref={voiceInputRef}
