221	                      e.target.value = '';
222	                    }}
223	                  />
224	                  <button
225	                    onClick={() => voiceInputRef.current?.click()}
226	                    disabled={voiceMutation.isPending}
227	                    className="bg-gray-100 text-gray-600 px-3 rounded-lg text-sm font-medium disabled:opacity-60 self-end h-10"
228	                    title="Send voice message"
229	                  >
230	                    Voice
231	                  </button>
232	                </div>
233	              </div>
234	            </>
235	          )}
236	        </div>
237	      </div>
238	    </div>
239	  );
240	}
