1	import React from 'react';
2	import { render, type RenderOptions } from '@testing-library/react';
3	import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
4	import { BrowserRouter } from 'react-router-dom';
5	
6	function createTestQueryClient() {
7	  return new QueryClient({
8	    defaultOptions: {
9	      queries: { retry: false },
10	      mutations: { retry: false },
11	    },
12	  });
13	}
14	
15	export function renderWithProviders(
16	  ui: React.ReactElement,
17	  options?: Omit<RenderOptions, 'wrapper'>,
18	) {
19	  const testQueryClient = createTestQueryClient();
20	
21	  function Wrapper({ children }: { children: React.ReactNode }) {
22	    return (
23	      <QueryClientProvider client={testQueryClient}>
24	        <BrowserRouter>{children}</BrowserRouter>
25	      </QueryClientProvider>
26	    );
27	  }
28	
29	  return { ...render(ui, { wrapper: Wrapper, ...options }), queryClient: testQueryClient };
30	}
