1	import axios from 'axios';
2	import { useAuthStore } from '../store/auth.store';
3	
4	const api = axios.create({
5	  baseURL: (import.meta.env.VITE_API_BASE_URL ?? 'http://localhost:3001') + '/api',
6	  headers: { 'Content-Type': 'application/json' },
7	});
8	
9	api.interceptors.request.use((config) => {
10	  const token = useAuthStore.getState().token;
11	  if (token) {
12	    config.headers.Authorization = `Bearer ${token}`;
13	  }
14	  return config;
15	});
16	
17	api.interceptors.response.use(
18	  (response) => response,
19	  (error) => {
20	    if (error.response?.status === 401) {
21	      useAuthStore.getState().logout();
22	      window.location.href = '/login';
23	    }
24	    return Promise.reject(error);
25	  },
26	);
27	
28	export default api;
29	
30	export interface PaginatedResponse<T> {
31	  items: T[];
32	  total: number;
33	  page: number;
34	  limit: number;
35	  totalPages: number;
36	  fallback?: { similarBreed: T[]; trending: T[] };
37	}
38	
39	export interface ApiEnvelope<T> {
40	  code: number;
41	  msg: string;
42	  data: T;
43	}
44	
45	export async function apiGet<T>(url: string, params?: Record<string, unknown>): Promise<T> {
46	  const res = await api.get<ApiEnvelope<T>>(url, { params });
47	  return res.data.data;
48	}
49	
50	export async function apiPost<T>(url: string, body?: unknown): Promise<T> {
51	  const res = await api.post<ApiEnvelope<T>>(url, body);
52	  return res.data.data;
53	}
54	
55	export async function apiPut<T>(url: string, body?: unknown): Promise<T> {
56	  const res = await api.put<ApiEnvelope<T>>(url, body);
57	  return res.data.data;
58	}
59	
60	export async function apiPatch<T>(url: string, body?: unknown): Promise<T> {
61	  const res = await api.patch<ApiEnvelope<T>>(url, body);
62	  return res.data.data;
63	}
64	
65	export async function apiDelete<T = void>(url: string): Promise<T> {
66	  const res = await api.delete<ApiEnvelope<T>>(url);
67	  return res.data.data;
68	}
69	
70	export async function apiPostFormData<T>(url: string, formData: FormData): Promise<T> {
71	  const res = await api.post<ApiEnvelope<T>>(url, formData, {
72	    headers: { 'Content-Type': 'multipart/form-data' },
73	  });
74	  return res.data.data;
75	}
