1	import {
2	  Injectable,
3	  NotFoundException,
4	  OnModuleInit,
5	  OnModuleDestroy,
6	  HttpException,
7	  HttpStatus,
8	} from '@nestjs/common';
9	import { InjectRepository } from '@nestjs/typeorm';
10	import { Repository, In, LessThan, DataSource } from 'typeorm';
11	import * as fs from 'fs';
12	import * as path from 'path';
13	import { ExportJob, ExportJobStatus } from '../database/entities/export-job.entity';
14	import { CreateExportJobDto } from './dto/export.dto';
15	import { EncryptionService } from '../common/encryption/encryption.service';
16	import { logger } from '../common/logger/winston.logger';
17	import { safeDeleteFile } from './export-file.util';
18	
19	const MAX_CONCURRENT = 2;
20	const EXPIRY_DAYS = 7;
21	const EXPORT_DIR = '/tmp/exports';
22	const POLL_INTERVAL_MS = 5000;
23	
24	@Injectable()
25	export class ExportsService implements OnModuleInit, OnModuleDestroy {
26	  private pollTimer: ReturnType<typeof setInterval> | null = null;
27	
28	  constructor(
29	    @InjectRepository(ExportJob)
30	    private readonly exportRepo: Repository<ExportJob>,
31	    private readonly dataSource: DataSource,
32	    private readonly encryption: EncryptionService,
33	  ) {}
34	
35	  onModuleInit() {
36	    if (!fs.existsSync(EXPORT_DIR)) {
37	      fs.mkdirSync(EXPORT_DIR, { recursive: true });
38	    }
39	    this.pollTimer = setInterval(() => this.processPendingJobs(), POLL_INTERVAL_MS);
40	  }
41	
42	  onModuleDestroy() {
43	    if (this.pollTimer) clearInterval(this.pollTimer);
44	  }
45	
46	  async createJob(requesterId: string, dto: CreateExportJobDto): Promise<ExportJob> {
47	    const expiresAt = new Date();
48	    expiresAt.setDate(expiresAt.getDate() + EXPIRY_DAYS);
49	
50	    const job = this.exportRepo.create({
51	      requesterId,
52	      status: ExportJobStatus.QUEUED,
53	      params: { type: dto.type, filters: dto.filters ?? {} },
54	      expiresAt,
55	    });
56	
57	    return this.exportRepo.save(job);
58	  }
59	
60	  async findAll(requesterId: string, role: string): Promise<ExportJob[]> {
61	    if (role === 'admin') {
62	      return this.exportRepo.find({ order: { createdAt: 'DESC' } });
63	    }
64	    return this.exportRepo.find({
65	      where: { requesterId },
66	      order: { createdAt: 'DESC' },
67	    });
68	  }
69	
70	  async getJobStatus(id: string, requesterId: string, role: string): Promise<ExportJob> {
71	    const job = await this.exportRepo.findOne({ where: { id } });
72	    if (!job) throw new NotFoundException('Export job not found');
73	    if (role !== 'admin' && job.requesterId !== requesterId) {
74	      throw new NotFoundException('Export job not found');
75	    }
76	    return job;
77	  }
78	
79	  async downloadFile(
80	    id: string,
81	    requesterId: string,
82	    role: string,
83	  ): Promise<{ filePath: string; fileName: string }> {
84	    const job = await this.getJobStatus(id, requesterId, role);
85	
86	    if (job.status === ExportJobStatus.EXPIRED) {
87	      throw new NotFoundException('Export file has expired');
88	    }
89	    if (job.status !== ExportJobStatus.DONE || !job.filePath) {
90	      throw new HttpException('Export is still processing', HttpStatus.ACCEPTED);
91	    }
92	    if (job.expiresAt && new Date() > new Date(job.expiresAt)) {
93	      await this.expireJob(job);
94	      throw new NotFoundException('Export file has expired');
95	    }
96	
97	    return { filePath: job.filePath, fileName: `export-${id}.csv` };
98	  }
99	
100	  private async processPendingJobs(): Promise<void> {
101	    try {
102	      await this.expireOldJobs();
103	
104	      const runningCount = await this.exportRepo.count({
105	        where: { status: ExportJobStatus.RUNNING },
106	      });
107	      if (runningCount >= MAX_CONCURRENT) return;
108	
109	      const slotsAvailable = MAX_CONCURRENT - runningCount;
110	      const queued = await this.exportRepo.find({
111	        where: { status: ExportJobStatus.QUEUED },
112	        order: { createdAt: 'ASC' },
113	        take: slotsAvailable,
114	      });
115	
116	      for (const job of queued) {
117	        this.processJob(job).catch((err) => {
118	          logger.error(`Export job ${job.id} failed: ${err}`, { context: 'ExportProcessor' });
119	        });
120	      }
121	    } catch (err) {
122	      logger.error(`Export poll error: ${err}`, { context: 'ExportProcessor' });
123	    }
124	  }
125	
126	  private async processJob(job: ExportJob): Promise<void> {
127	    await this.exportRepo.update(job.id, { status: ExportJobStatus.RUNNING });
128	
129	    try {
130	      const type = job.params.type as string;
131	      const filters = (job.params.filters ?? {}) as Record<string, unknown>;
132	      const requester = await this.dataSource
133	        .getRepository('User')
134	        .findOne({ where: { id: job.requesterId } });
135	      const isAdmin = !!(requester && (requester as any).role === 'admin');
136	
137	      let csv = '';
138	
139	      switch (type) {
140	        case 'listings':
141	          csv = await this.exportListings(filters, isAdmin);
142	          break;
143	        case 'conversations':
144	          csv = await this.exportConversations(filters, isAdmin);
145	          break;
146	        case 'settlements':
147	          csv = await this.exportSettlements(filters, isAdmin);
148	          break;
149	        case 'audit':
150	          csv = await this.exportAudit(filters);
151	          break;
152	        default:
153	          csv = 'id\nno_data';
154	      }
155	
156	      const filePath = path.join(EXPORT_DIR, `${job.id}.csv`);
157	      fs.writeFileSync(filePath, csv, 'utf-8');
158	
159	      await this.exportRepo.update(job.id, {
160	        status: ExportJobStatus.DONE,
161	        filePath,
162	      });
163	    } catch (err) {
164	      await this.exportRepo.update(job.id, { status: ExportJobStatus.FAILED });
165	      throw err;
166	    }
167	  }
168	
169	  private async exportListings(
170	    filters: Record<string, unknown>,
171	    isAdmin: boolean,
172	  ): Promise<string> {
173	    const qb = this.dataSource
174	      .getRepository('Listing')
175	      .createQueryBuilder('l')
176	      .leftJoinAndSelect('l.vendor', 'v')
177	      .orderBy('l.createdAt', 'DESC');
178	
179	    if (filters.status) qb.andWhere('l.status = :status', { status: filters.status });
180	    if (filters.breed) qb.andWhere('l.breed = :breed', { breed: filters.breed });
181	
182	    const listings = await qb.getMany();
183	    const header = 'ID,Title,Breed,Region,Price,Status,Vendor,Created At';
184	    const rows = listings.map((l: any) =>
185	      [l.id, esc(l.title), esc(l.breed), esc(l.region), l.priceUsd, l.status, l.vendor?.username ?? '', l.createdAt].join(','),
186	    );
187	    return [header, ...rows].join('\n');
188	  }
189	
190	  private async exportConversations(
191	    filters: Record<string, unknown>,
192	    isAdmin: boolean,
193	  ): Promise<string> {
194	    const qb = this.dataSource
195	      .getRepository('Conversation')
196	      .createQueryBuilder('c')
197	      .orderBy('c.createdAt', 'DESC');
198	
199	    const conversations = await qb.getMany();
200	    const header = 'ID,Listing ID,Vendor ID,Archived,Disputed,Created At';
201	    const rows = conversations.map((c: any) =>
202	      [c.id, c.listingId, c.vendorId, c.isArchived, c.isDisputed, c.createdAt].join(','),
203	    );
204	    return [header, ...rows].join('\n');
205	  }
206	
207	  private async exportSettlements(
208	    filters: Record<string, unknown>,
209	    isAdmin: boolean,
210	  ): Promise<string> {
211	    const qb = this.dataSource
212	      .getRepository('Settlement')
213	      .createQueryBuilder('s')
214	      .leftJoinAndSelect('s.vendor', 'v')
215	      .orderBy('s.createdAt', 'DESC');
216	
217	    if (filters.month) qb.andWhere('s.month = :month', { month: filters.month });
218	    if (filters.status) qb.andWhere('s.status = :status', { status: filters.status });
219	
220	    const settlements = await qb.getMany();
221	    const header = 'ID,Vendor,Month,Total Charges,Tax Amount,Status,Created At';
222	    const rows = settlements.map((s: any) => {
223	      const vendorEmail = s.vendor?.email
224	        ? isAdmin
225	          ? this.encryption.decrypt(s.vendor.email)
226	          : '***masked***'
227	        : 'N/A';
228	      return [s.id, s.vendor?.username ?? '', s.month, s.totalCharges, s.taxAmount, s.status, s.createdAt].join(',');
229	    });
230	    return [header, ...rows].join('\n');
231	  }
232	
233	  private async exportAudit(filters: Record<string, unknown>): Promise<string> {
234	    const qb = this.dataSource
235	      .getRepository('AuditLog')
236	      .createQueryBuilder('a')
237	      .orderBy('a.createdAt', 'DESC');
238	
239	    if (filters.action) qb.andWhere('a.action = :action', { action: filters.action });
240	    if (filters.entityType) qb.andWhere('a.entityType = :entityType', { entityType: filters.entityType });
241	
242	    const logs = await qb.limit(10000).getMany();
243	    const header = 'ID,Action,Actor,Entity Type,Entity ID,Hash,Created At';
244	    const rows = logs.map((l: any) =>
245	      [l.id, l.action, l.actorId, l.entityType, l.entityId ?? '', l.hash, l.createdAt].join(','),
246	    );
247	    return [header, ...rows].join('\n');
248	  }
249	
250	  private async expireOldJobs(): Promise<void> {
251	    const now = new Date();
252	    const toExpire = await this.exportRepo.find({
253	      where: { status: ExportJobStatus.DONE, expiresAt: LessThan(now) },
254	    });
255	    for (const job of toExpire) {
256	      await this.expireJob(job).catch((err: unknown) => {
257	        logger.error(`Failed to expire job ${job.id}: ${err}`, { context: 'ExportExpiry' });
258	      });
259	    }
260	  }
261	
262	  /**
263	   * Expire a single export job atomically:
264	   *  1. Delete the file from disk (best-effort — ENOENT is treated as already-gone).
265	   *  2. UPDATE WHERE status='done' to EXPIRED + filePath=null (compare-and-set).
266	   *     If affected=0, another worker already expired it — safe to ignore.
267	   *
268	   * Exposed as public so it can be driven directly from tests and from
269	   * downloadFile's inline expiry path.
270	   */
271	  async expireJob(job: ExportJob): Promise<void> {
272	    if (job.filePath) {
273	      const result = safeDeleteFile(job.filePath);
274	      if (result.deleted) {
275	        logger.info(`Deleted export file: ${job.filePath}`, { context: 'ExportExpiry' });
276	      } else {
277	        // file_not_found is expected when a previous expiry run already removed it
278	        logger.warn(
279	          `Export file not deleted (${result.error}): ${job.filePath}`,
280	          { context: 'ExportExpiry' },
281	        );
282	      }
283	    }
284	
285	    // Atomic compare-and-set: only commits if this worker wins the race
286	    const updateResult = await this.exportRepo
287	      .createQueryBuilder()
288	      .update()
289	      .set({ status: ExportJobStatus.EXPIRED, filePath: () => 'NULL' })
290	      .where('id = :id', { id: job.id })
291	      .andWhere('status = :done', { done: ExportJobStatus.DONE })
292	      .execute();
293	
294	    if (!updateResult.affected || updateResult.affected === 0) {
295	      logger.info(
296	        `Export job ${job.id} already expired by concurrent worker — skipping`,
297	        { context: 'ExportExpiry' },
298	      );
299	    }
300	  }
301	}
302	
303	function esc(val: string): string {
304	  if (!val) return '';
305	  return `"${val.replace(/"/g, '""')}"`;
306	}
