30	function makeQb(affected = 1): any {
31	  const qb: any = {
32	    update: () => qb,
33	    set: () => qb,
34	    where: () => qb,
35	    andWhere: () => qb,
36	    execute: jest.fn().mockResolvedValue({ affected }),
37	  };
