1	import {
2	  Injectable,
3	  NotFoundException,
4	  ForbiddenException,
5	  OnModuleInit,
6	  OnModuleDestroy,
7	  HttpException,
8	  HttpStatus,
9	} from '@nestjs/common';
10	import { InjectRepository } from '@nestjs/typeorm';
11	import { Repository, In, LessThan, DataSource } from 'typeorm';
12	import * as fs from 'fs';
13	import * as path from 'path';
14	import { ExportJob, ExportJobStatus } from '../database/entities/export-job.entity';
15	import { CreateExportJobDto } from './dto/export.dto';
16	import { EncryptionService } from '../common/encryption/encryption.service';
17	import { logger } from '../common/logger/winston.logger';
18	import { safeDeleteFile } from './export-file.util';
19	
20	const MAX_CONCURRENT = 2;
21	const EXPIRY_DAYS = 7;
22	const EXPORT_DIR = '/tmp/exports';
23	const POLL_INTERVAL_MS = 5000;
24	
25	@Injectable()
26	export class ExportsService implements OnModuleInit, OnModuleDestroy {
27	  private pollTimer: ReturnType<typeof setInterval> | null = null;
28	
29	  constructor(
30	    @InjectRepository(ExportJob)
31	    private readonly exportRepo: Repository<ExportJob>,
32	    private readonly dataSource: DataSource,
33	    private readonly encryption: EncryptionService,
34	  ) {}
35	
36	  onModuleInit() {
37	    if (!fs.existsSync(EXPORT_DIR)) {
38	      fs.mkdirSync(EXPORT_DIR, { recursive: true });
39	    }
40	    this.pollTimer = setInterval(() => this.processPendingJobs(), POLL_INTERVAL_MS);
41	  }
42	
43	  onModuleDestroy() {
44	    if (this.pollTimer) clearInterval(this.pollTimer);
45	  }
46	
47	  async createJob(requesterId: string, requesterRole: string, dto: CreateExportJobDto): Promise<ExportJob> {
48	    // Audit exports contain internal security data — admin only
49	    if (dto.type === 'audit' && requesterRole !== 'admin') {
50	      throw new ForbiddenException('Audit exports are restricted to admins');
51	    }
52	    // ops_reviewer and finance_admin may only export settlements
53	    if (
54	      (requesterRole === 'ops_reviewer' || requesterRole === 'finance_admin') &&
55	      dto.type !== 'settlements'
56	    ) {
57	      throw new ForbiddenException(`Role ${requesterRole} may only export settlements`);
58	    }
59	
60	    const expiresAt = new Date();
61	    expiresAt.setDate(expiresAt.getDate() + EXPIRY_DAYS);
62	
63	    const job = this.exportRepo.create({
64	      requesterId,
65	      status: ExportJobStatus.QUEUED,
66	      params: { type: dto.type, filters: dto.filters ?? {} },
67	      expiresAt,
68	    });
69	
70	    return this.exportRepo.save(job);
71	  }
72	
73	  async findAll(requesterId: string, role: string): Promise<ExportJob[]> {
74	    if (role === 'admin') {
75	      return this.exportRepo.find({ order: { createdAt: 'DESC' } });
76	    }
77	    return this.exportRepo.find({
78	      where: { requesterId },
79	      order: { createdAt: 'DESC' },
80	    });
81	  }
82	
83	  async getJobStatus(id: string, requesterId: string, role: string): Promise<ExportJob> {
84	    const job = await this.exportRepo.findOne({ where: { id } });
85	    if (!job) throw new NotFoundException('Export job not found');
86	    if (role !== 'admin' && job.requesterId !== requesterId) {
87	      throw new NotFoundException('Export job not found');
88	    }
89	    return job;
90	  }
91	
92	  async downloadFile(
93	    id: string,
94	    requesterId: string,
95	    role: string,
96	  ): Promise<{ filePath: string; fileName: string }> {
97	    const job = await this.getJobStatus(id, requesterId, role);
98	
99	    if (job.status === ExportJobStatus.EXPIRED) {
100	      throw new NotFoundException('Export file has expired');
101	    }
102	    if (job.status !== ExportJobStatus.DONE || !job.filePath) {
103	      throw new HttpException('Export is still processing', HttpStatus.ACCEPTED);
104	    }
105	    if (job.expiresAt && new Date() > new Date(job.expiresAt)) {
106	      await this.expireJob(job);
107	      throw new NotFoundException('Export file has expired');
108	    }
109	
110	    return { filePath: job.filePath, fileName: `export-${id}.csv` };
111	  }
112	
113	  private async processPendingJobs(): Promise<void> {
114	    try {
115	      await this.expireOldJobs();
116	
117	      const runningCount = await this.exportRepo.count({
118	        where: { status: ExportJobStatus.RUNNING },
119	      });
120	      if (runningCount >= MAX_CONCURRENT) return;
121	
122	      const slotsAvailable = MAX_CONCURRENT - runningCount;
123	      const queued = await this.exportRepo.find({
124	        where: { status: ExportJobStatus.QUEUED },
125	        order: { createdAt: 'ASC' },
126	        take: slotsAvailable,
127	      });
128	
129	      for (const job of queued) {
130	        this.processJob(job).catch((err) => {
131	          logger.error(`Export job ${job.id} failed: ${err}`, { context: 'ExportProcessor' });
132	        });
133	      }
134	    } catch (err) {
135	      logger.error(`Export poll error: ${err}`, { context: 'ExportProcessor' });
136	    }
137	  }
138	
139	  private async processJob(job: ExportJob): Promise<void> {
140	    await this.exportRepo.update(job.id, { status: ExportJobStatus.RUNNING });
141	
142	    try {
143	      const type = job.params.type as string;
144	      const filters = (job.params.filters ?? {}) as Record<string, unknown>;
145	      const requester = await this.dataSource
146	        .getRepository('User')
147	        .findOne({ where: { id: job.requesterId } });
148	      const requesterRole: string = (requester as any)?.role ?? 'vendor';
149	      const isAdmin = requesterRole === 'admin';
150	
151	      let csv = '';
152	
153	      switch (type) {
154	        case 'listings':
155	          csv = await this.exportListings(filters, isAdmin, job.requesterId, requesterRole);
156	          break;
157	        case 'conversations':
158	          csv = await this.exportConversations(filters, isAdmin, job.requesterId, requesterRole);
159	          break;
160	        case 'settlements':
161	          csv = await this.exportSettlements(filters, isAdmin, job.requesterId, requesterRole);
162	          break;
163	        case 'audit':
164	          csv = await this.exportAudit(filters);
165	          break;
166	        default:
167	          csv = 'id\nno_data';
168	      }
169	
170	      const filePath = path.join(EXPORT_DIR, `${job.id}.csv`);
171	      fs.writeFileSync(filePath, csv, 'utf-8');
172	
173	      await this.exportRepo.update(job.id, {
174	        status: ExportJobStatus.DONE,
175	        filePath,
176	      });
177	    } catch (err) {
178	      await this.exportRepo.update(job.id, { status: ExportJobStatus.FAILED });
179	      throw err;
180	    }
181	  }
182	
183	  private async exportListings(
184	    filters: Record<string, unknown>,
185	    isAdmin: boolean,
186	    requesterId: string,
187	    requesterRole: string,
188	  ): Promise<string> {
189	    const qb = this.dataSource
190	      .getRepository('Listing')
191	      .createQueryBuilder('l')
192	      .leftJoinAndSelect('l.vendor', 'v')
193	      .orderBy('l.createdAt', 'DESC');
194	
195	    // Vendors see only their own listings
196	    if (!isAdmin) qb.andWhere('l.vendorId = :requesterId', { requesterId });
197	
198	    if (filters.status) qb.andWhere('l.status = :status', { status: filters.status });
199	    if (filters.breed) qb.andWhere('l.breed = :breed', { breed: filters.breed });
200	
201	    const listings = await qb.getMany();
202	    const header = 'ID,Title,Breed,Region,Price,Status,Vendor,Created At';
203	    const rows = listings.map((l: any) =>
204	      [l.id, esc(l.title), esc(l.breed), esc(l.region), l.priceUsd, l.status, l.vendor?.username ?? '', l.createdAt].join(','),
205	    );
206	    return [watermark(requesterRole, requesterId), header, ...rows].join('\n');
207	  }
208	
209	  private async exportConversations(
210	    filters: Record<string, unknown>,
211	    isAdmin: boolean,
212	    requesterId: string,
213	    requesterRole: string,
214	  ): Promise<string> {
215	    const qb = this.dataSource
216	      .getRepository('Conversation')
217	      .createQueryBuilder('c')
218	      .orderBy('c.createdAt', 'DESC');
219	
220	    // Vendors see only conversations where they are the vendor party
221	    if (!isAdmin) qb.andWhere('c.vendorId = :requesterId', { requesterId });
222	
223	    const conversations = await qb.getMany();
224	    const header = 'ID,Listing ID,Vendor ID,Archived,Disputed,Created At';
225	    const rows = conversations.map((c: any) =>
226	      [c.id, c.listingId, c.vendorId, c.isArchived, c.isDisputed, c.createdAt].join(','),
227	    );
228	    return [watermark(requesterRole, requesterId), header, ...rows].join('\n');
229	  }
230	
231	  private async exportSettlements(
232	    filters: Record<string, unknown>,
233	    isAdmin: boolean,
234	    requesterId: string,
235	    requesterRole: string,
236	  ): Promise<string> {
237	    const qb = this.dataSource
238	      .getRepository('Settlement')
239	      .createQueryBuilder('s')
240	      .leftJoinAndSelect('s.vendor', 'v')
241	      .orderBy('s.createdAt', 'DESC');
242	
243	    // Vendors see only their own settlements
244	    if (requesterRole === 'vendor') qb.andWhere('s.vendorId = :requesterId', { requesterId });
245	
246	    if (filters.month) qb.andWhere('s.month = :month', { month: filters.month });
247	    if (filters.status) qb.andWhere('s.status = :status', { status: filters.status });
248	
249	    const settlements = await qb.getMany();
250	    const header = 'ID,Vendor,Vendor Email,Month,Total Charges,Tax Amount,Status,Created At';
251	    const rows = settlements.map((s: any) => {
252	      const vendorEmail = s.vendor?.email
253	        ? isAdmin
254	          ? this.encryption.decrypt(s.vendor.email)
255	          : '***'
256	        : 'N/A';
257	      return [s.id, s.vendor?.username ?? '', vendorEmail, s.month, s.totalCharges, s.taxAmount, s.status, s.createdAt].join(',');
258	    });
259	    return [watermark(requesterRole, requesterId), header, ...rows].join('\n');
260	  }
261	
262	  private async exportAudit(filters: Record<string, unknown>): Promise<string> {
263	    const qb = this.dataSource
264	      .getRepository('AuditLog')
265	      .createQueryBuilder('a')
266	      .orderBy('a.createdAt', 'DESC');
267	
268	    if (filters.action) qb.andWhere('a.action = :action', { action: filters.action });
269	    if (filters.entityType) qb.andWhere('a.entityType = :entityType', { entityType: filters.entityType });
270	
271	    const logs = await qb.limit(10000).getMany();
272	    const header = 'ID,Action,Actor,Entity Type,Entity ID,Hash,Created At';
273	    const rows = logs.map((l: any) =>
274	      [l.id, l.action, l.actorId, l.entityType, l.entityId ?? '', l.hash, l.createdAt].join(','),
275	    );
276	    return [header, ...rows].join('\n');
277	  }
278	
279	  private async expireOldJobs(): Promise<void> {
280	    const now = new Date();
281	    const toExpire = await this.exportRepo.find({
282	      where: { status: ExportJobStatus.DONE, expiresAt: LessThan(now) },
283	    });
284	    for (const job of toExpire) {
285	      await this.expireJob(job).catch((err: unknown) => {
286	        logger.error(`Failed to expire job ${job.id}: ${err}`, { context: 'ExportExpiry' });
287	      });
288	    }
289	  }
290	
291	  /**
292	   * Expire a single export job atomically:
293	   *  1. Delete the file from disk (best-effort — ENOENT is treated as already-gone).
294	   *  2. UPDATE WHERE status='done' to EXPIRED + filePath=null (compare-and-set).
295	   *     If affected=0, another worker already expired it — safe to ignore.
296	   *
297	   * Exposed as public so it can be driven directly from tests and from
298	   * downloadFile's inline expiry path.
299	   */
300	  async expireJob(job: ExportJob): Promise<void> {
301	    if (job.filePath) {
302	      const result = safeDeleteFile(job.filePath);
303	      if (result.deleted) {
304	        logger.info(`Deleted export file: ${job.filePath}`, { context: 'ExportExpiry' });
305	      } else {
306	        // file_not_found is expected when a previous expiry run already removed it
307	        logger.warn(
308	          `Export file not deleted (${result.error}): ${job.filePath}`,
309	          { context: 'ExportExpiry' },
310	        );
311	      }
312	    }
313	
314	    // Atomic compare-and-set: only commits if this worker wins the race
315	    const updateResult = await this.exportRepo
316	      .createQueryBuilder()
317	      .update()
318	      .set({ status: ExportJobStatus.EXPIRED, filePath: () => 'NULL' })
319	      .where('id = :id', { id: job.id })
320	      .andWhere('status = :done', { done: ExportJobStatus.DONE })
321	      .execute();
322	
323	    if (!updateResult.affected || updateResult.affected === 0) {
324	      logger.info(
325	        `Export job ${job.id} already expired by concurrent worker — skipping`,
326	        { context: 'ExportExpiry' },
327	      );
328	    }
329	  }
330	}
331	
332	function esc(val: string): string {
333	  if (!val) return '';
334	  return `"${val.replace(/"/g, '""')}"`;
335	}
336	
337	/** Prepend a comment row identifying who generated this file and when. */
338	function watermark(role: string, requesterId: string): string {
339	  return `# Generated for: ${role} / ${requesterId} at ${new Date().toISOString()}`;
340	}
