236	    return formatExportCsv(header, rows, ctx);
237	  }
238	
239	  private async exportSettlements(
240	    filters: Record<string, unknown>,
241	    ctx: ExportContext,
242	  ): Promise<string> {
243	    const qb = this.dataSource
244	      .getRepository('Settlement')
245	      .createQueryBuilder('s')
246	      .leftJoinAndSelect('s.vendor', 'v')
247	      .orderBy('s.createdAt', 'DESC');
248	
249	    if (ctx.requesterRole === 'vendor') {
250	      qb.andWhere('s.vendorId = :requesterId', { requesterId: ctx.requesterId });
251	    }
252	    if (filters.month) qb.andWhere('s.month = :month', { month: filters.month });
253	    if (filters.status) qb.andWhere('s.status = :status', { status: filters.status });
254	
255	    const settlements = await qb.getMany();
256	    const header = 'ID,Vendor,Vendor Email,Month,Total Charges,Tax Amount,Status,Created At';
257	    const rows = settlements.map((s: any) =>
258	      [
259	        s.id, s.vendor?.username ?? '', ctx.maskEmail(s.vendor?.email),
260	        s.month, s.totalCharges, s.taxAmount, s.status, s.createdAt,
261	      ].join(','),
262	    );
263	    return formatExportCsv(header, rows, ctx);
264	  }
265	
266	  private async exportAudit(
267	    filters: Record<string, unknown>,
268	    ctx: ExportContext,
269	  ): Promise<string> {
270	    const qb = this.dataSource
271	      .getRepository('AuditLog')
272	      .createQueryBuilder('a')
273	      .orderBy('a.createdAt', 'DESC');
274	
275	    if (filters.action) qb.andWhere('a.action = :action', { action: filters.action });
276	    if (filters.entityType) qb.andWhere('a.entityType = :entityType', { entityType: filters.entityType });
277	
278	    const logs = await qb.limit(10000).getMany();
279	    const header = 'ID,Action,Actor,Entity Type,Entity ID,Hash,Created At';
280	    const rows = logs.map((l: any) =>
281	      [l.id, l.action, l.actorId, l.entityType, l.entityId ?? '', l.hash, l.createdAt].join(','),
282	    );
283	    return formatExportCsv(header, rows, ctx);
284	  }
285	
286	  private async expireOldJobs(): Promise<void> {
287	    const now = new Date();
288	    const toExpire = await this.exportRepo.find({
289	      where: { status: ExportJobStatus.DONE, expiresAt: LessThan(now) },
290	    });
291	    for (const job of toExpire) {
292	      await this.expireJob(job).catch((err: unknown) => {
293	        logger.error(`Failed to expire job ${job.id}: ${err}`, { context: 'ExportExpiry' });
294	      });
295	    }
296	  }
297	
298	  /**
299	   * Expire a single export job atomically:
300	   *  1. Delete the file from disk (best-effort — ENOENT is treated as already-gone).
301	   *  2. UPDATE WHERE status='done' to EXPIRED + filePath=null (compare-and-set).
302	   *     If affected=0, another worker already expired it — safe to ignore.
303	   *
304	   * Exposed as public so it can be driven directly from tests and from
305	   * downloadFile's inline expiry path.
306	   */
307	  async expireJob(job: ExportJob): Promise<void> {
308	    if (job.filePath) {
309	      const result = safeDeleteFile(job.filePath);
310	      if (result.deleted) {
311	        logger.info(`Deleted export file: ${job.filePath}`, { context: 'ExportExpiry' });
312	      } else {
313	        // file_not_found is expected when a previous expiry run already removed it
314	        logger.warn(
315	          `Export file not deleted (${result.error}): ${job.filePath}`,
316	          { context: 'ExportExpiry' },
317	        );
318	      }
319	    }
320	
321	    // Atomic compare-and-set: only commits if this worker wins the race
322	    const updateResult = await this.exportRepo
323	      .createQueryBuilder()
324	      .update()
325	      .set({ status: ExportJobStatus.EXPIRED, filePath: () => 'NULL' })
326	      .where('id = :id', { id: job.id })
327	      .andWhere('status = :done', { done: ExportJobStatus.DONE })
328	      .execute();
329	
330	    if (!updateResult.affected || updateResult.affected === 0) {
331	      logger.info(
332	        `Export job ${job.id} already expired by concurrent worker — skipping`,
333	        { context: 'ExportExpiry' },
334	      );
335	    }
336	  }
337	}
338	
339	/** Shared context threaded through every export function. */
340	interface ExportContext {
341	  requesterId: string;
342	  requesterRole: string;
343	  isAdmin: boolean;
344	  /** Decrypt if admin, mask to '***' otherwise, 'N/A' if null. */
345	  maskEmail: (encrypted: string | null | undefined) => string;
346	}
347	
348	function esc(val: string): string {
349	  if (!val) return '';
350	  return `"${val.replace(/"/g, '""')}"`;
351	}
352	
353	/**
354	 * Central formatter — every export flows through here.
355	 * Guarantees a watermark row is always present.
356	 */
357	function formatExportCsv(header: string, rows: string[], ctx: ExportContext): string {
358	  const wm = `# Generated for: ${ctx.requesterRole} / ${ctx.requesterId} at ${new Date().toISOString()}`;
359	  return [wm, header, ...rows].join('\n');
360	}
