1	/**
2	 * Centralized secret resolution with fail-fast enforcement.
3	 *
4	 * In production (NODE_ENV === 'production') every security-critical secret
5	 * MUST be provided via the environment — missing values crash the process
6	 * immediately so a misconfigured deploy never starts silently.
7	 *
8	 * In development and test the well-known defaults continue to work so that
9	 * `docker compose up` and `jest` need zero local setup.
10	 */
11	
12	const DEV_JWT_SECRET = 'local_dev_jwt_secret_change_in_prod';
13	const DEV_ENCRYPTION_KEY = 'local_dev_encryption_key_change_in_prod';
14	
15	function isProduction(): boolean {
16	  return process.env.NODE_ENV === 'production';
17	}
18	
19	/**
20	 * Resolve a secret from the environment.
21	 * Throws at import-time in production if the variable is missing or matches a
22	 * known insecure default, so the app never boots with weak credentials.
23	 */
24	function requireSecret(envVar: string, devDefault: string): string {
25	  const value = process.env[envVar];
26	
27	  if (isProduction()) {
28	    if (!value) {
29	      throw new Error(
30	        `FATAL: ${envVar} is not set. ` +
31	          'All security-critical secrets must be provided via environment variables in production. ' +
32	          'See .env.example for the full list.',
33	      );
34	    }
35	    if (value === devDefault) {
36	      throw new Error(
37	        `FATAL: ${envVar} is still set to the insecure development default. ` +
38	          'Generate a cryptographically random value before deploying to production.',
39	      );
40	    }
41	    return value;
42	  }
43	
44	  // Dev / test: fall back to the well-known default
45	  return value || devDefault;
46	}
47	
48	export const JWT_SECRET = requireSecret('JWT_SECRET', DEV_JWT_SECRET);
49	export const FIELD_ENCRYPTION_KEY = requireSecret('FIELD_ENCRYPTION_KEY', DEV_ENCRYPTION_KEY);
